import type { ColumnSchema } from "lemma-sdk";

const ENUM_PALETTE = [
  { bg: "bg-blue-100 dark:bg-blue-500/15", text: "text-blue-700 dark:text-blue-300" },
  { bg: "bg-emerald-100 dark:bg-emerald-500/15", text: "text-emerald-700 dark:text-emerald-300" },
  { bg: "bg-violet-100 dark:bg-violet-500/15", text: "text-violet-700 dark:text-violet-300" },
  { bg: "bg-orange-100 dark:bg-orange-500/15", text: "text-orange-700 dark:text-orange-300" },
  { bg: "bg-pink-100 dark:bg-pink-500/15", text: "text-pink-700 dark:text-pink-300" },
  { bg: "bg-indigo-100 dark:bg-indigo-500/15", text: "text-indigo-700 dark:text-indigo-300" },
  { bg: "bg-teal-100 dark:bg-teal-500/15", text: "text-teal-700 dark:text-teal-300" },
  { bg: "bg-amber-100 dark:bg-amber-500/15", text: "text-amber-700 dark:text-amber-300" },
  { bg: "bg-cyan-100 dark:bg-cyan-500/15", text: "text-cyan-700 dark:text-cyan-300" },
  { bg: "bg-rose-100 dark:bg-rose-500/15", text: "text-rose-700 dark:text-rose-300" },
] as const;

function stableIndex(value: string, count: number): number {
  let hash = 0;
  for (let i = 0; i < value.length; i++) {
    hash = ((hash << 5) - hash + value.charCodeAt(i)) | 0;
  }
  return ((Math.abs(hash) % count) + count) % count;
}

export function enumColor(optionValue: string, options: string[]) {
  const idx = options.indexOf(optionValue);
  const i = idx >= 0 ? idx % ENUM_PALETTE.length : stableIndex(optionValue, ENUM_PALETTE.length);
  return ENUM_PALETTE[i];
}

export function enumPillClasses(optionValue: string, options: string[]): string {
  const c = enumColor(optionValue, options);
  return `inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${c.bg} ${c.text}`;
}

const TYPE_TINTS: Record<string, { bg: string; text: string }> = {
  TEXT: { bg: "bg-muted/45", text: "text-muted-foreground" },
  INTEGER: { bg: "bg-emerald-500/10", text: "text-emerald-700 dark:text-emerald-300" },
  FLOAT: { bg: "bg-blue-500/10", text: "text-blue-700 dark:text-blue-300" },
  BOOLEAN: { bg: "bg-primary/10", text: "text-primary" },
  DATE: { bg: "bg-amber-500/10", text: "text-amber-700 dark:text-amber-300" },
  DATETIME: { bg: "bg-amber-500/10", text: "text-amber-700 dark:text-amber-300" },
  ENUM: { bg: "bg-violet-500/10", text: "text-violet-700 dark:text-violet-300" },
  JSON: { bg: "bg-rose-500/10", text: "text-rose-700 dark:text-rose-300" },
  UUID: { bg: "bg-sky-500/10", text: "text-sky-700 dark:text-sky-300" },
  SERIAL: { bg: "bg-emerald-500/10", text: "text-emerald-700 dark:text-emerald-300" },
  VECTOR: { bg: "bg-muted/45", text: "text-muted-foreground" },
};

export function typeBadgeClasses(column: ColumnSchema): string {
  const tint = TYPE_TINTS[column.type] ?? TYPE_TINTS.TEXT;
  if (column.foreign_key) {
    return "rounded-full border border-border/50 bg-sky-500/10 px-1.5 py-0.5 text-[9px] font-medium normal-case text-sky-700 dark:text-sky-300";
  }
  return `rounded-full border border-border/50 ${tint.bg} px-1.5 py-0.5 text-[9px] font-medium normal-case ${tint.text}`;
}

export function isSystemField(column: ColumnSchema): boolean {
  return (
    column.system === true ||
    column.auto === true ||
    column.computed === true ||
    column.name === "id" ||
    column.name === "created_at" ||
    column.name === "updated_at" ||
    column.name === "creator_user_id" ||
    column.name === "sort_order"
  );
}

"use client"

import * as React from "react"
import type { ColumnSchema } from "lemma-sdk"
import { enumPillClasses, isSystemField } from "./records-enum-utils"

export type ForeignKeyLabelMap = Record<string, Record<string, string>>

const PRIMARY_FIELD_NAMES = ["title", "name", "label", "subject", "full_name", "primary_email"]

export function isUuidLike(value: string): boolean {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(value)
}

export function shortenIdentifier(value: unknown): string {
  const text = String(value ?? "")
  if (!text) return "—"
  if (isUuidLike(text)) return `${text.slice(0, 8)}…${text.slice(-4)}`
  return text.length > 28 ? `${text.slice(0, 24)}…` : text
}

export function pickPrimaryColumn(columns: ColumnSchema[]): ColumnSchema | undefined {
  return (
    columns.find((column) => PRIMARY_FIELD_NAMES.includes(column.name)) ??
    columns.find((column) => !isSystemField(column) && !column.foreign_key) ??
    columns.find((column) => !isSystemField(column)) ??
    columns[0]
  )
}

export function pickSecondaryColumns(
  columns: ColumnSchema[],
  primaryColumn?: ColumnSchema,
  options: { groupBy?: string; count?: number } = {},
): ColumnSchema[] {
  const count = options.count ?? 4
  return columns
    .filter((column) => !isSystemField(column))
    .filter((column) => column.name !== primaryColumn?.name)
    .filter((column) => column.name !== options.groupBy)
    .filter((column) => column.type !== "VECTOR" && column.type !== "JSON")
    .slice(0, count)
}

export function formatRecordFieldValue(
  value: unknown,
  column?: ColumnSchema,
  foreignKeyLabelMap?: ForeignKeyLabelMap,
): React.ReactNode {
  if (value == null || value === "") return "—"

  const text = String(value)
  if (column?.foreign_key) {
    const label = foreignKeyLabelMap?.[column.name]?.[text]
    return label || shortenIdentifier(text)
  }

  if (column?.type === "ENUM" && column.options?.length) {
    return <span className={enumPillClasses(text, column.options)}>{text}</span>
  }

  if (column?.type === "BOOLEAN") return value ? "Yes" : "No"

  if (column?.type === "DATE" || column?.type === "DATETIME") {
    const date = new Date(text)
    if (!Number.isNaN(date.getTime())) {
      return date.toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric" })
    }
  }

  if (column?.type === "UUID" || isUuidLike(text)) {
    return <span title={text}>{shortenIdentifier(text)}</span>
  }

  return text
}

"use client"

export type LemmaRecordsAppearance = "default" | "minimal" | "borderless" | "contained"
export type LemmaRecordsDensity = "compact" | "comfortable" | "spacious"
export type LemmaRecordsRadius = "none" | "sm" | "md" | "lg" | "xl"

export function recordsRadiusClassName(
  radius: LemmaRecordsRadius = "lg",
  target: "surface" | "control" | "pill" | "overlay" = "surface",
): string {
  if (radius === "none") return "rounded-none"

  if (radius === "sm") {
    if (target === "control" || target === "pill") return "rounded-sm"
    return "rounded-md"
  }

  if (radius === "md") {
    if (target === "surface" || target === "overlay") return "rounded-lg"
    return "rounded-md"
  }

  if (radius === "xl") {
    if (target === "pill") return "rounded-full"
    if (target === "control") return "rounded-xl"
    return "rounded-2xl"
  }

  if (target === "pill") return "rounded-full"
  if (target === "control") return "rounded-lg"
  return "rounded-xl"
}

"use client"

import * as React from "react"
import { Check, Loader2 } from "lucide-react"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectGroup, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Checkbox } from "@/components/ui/checkbox"
import { Textarea } from "@/components/ui/textarea"
import type { ColumnSchema } from "lemma-sdk"
import { enumPillClasses } from "./records-enum-utils"
import { shortenIdentifier } from "./records-display-utils"

interface EditableCellProps {
  value: unknown
  column: ColumnSchema
  onSave: (value: unknown) => Promise<void>
  readOnly?: boolean
  foreignKeyLabelMap?: Record<string, string>
}

export function EditableCell({ value, column, onSave, readOnly, foreignKeyLabelMap }: EditableCellProps) {
  const [editing, setEditing] = React.useState(false)
  const [draft, setDraft] = React.useState<string>(serialize(value, column.type))
  const [saving, setSaving] = React.useState(false)
  const inputRef = React.useRef<HTMLInputElement | HTMLTextAreaElement | null>(null)

  React.useEffect(() => {
    if (editing && inputRef.current) inputRef.current.focus()
  }, [editing])

  const startEdit = () => {
    if (readOnly) return
    setDraft(serialize(value, column.type))
    setEditing(true)
  }

  const save = async () => {
    const next = deserialize(draft, column)
    if (next === value && column.type !== "BOOLEAN") {
      setEditing(false)
      return
    }
    setSaving(true)
    try {
      await onSave(next)
      setEditing(false)
    } finally {
      setSaving(false)
    }
  }

  const cancel = () => {
    setDraft(serialize(value, column.type))
    setEditing(false)
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey && column.type !== "TEXT") save()
    if (e.key === "Escape") cancel()
  }

  if (readOnly) {
    return <span className="px-2 py-1.5 text-sm text-muted-foreground">{displayValue(value, column, foreignKeyLabelMap)}</span>
  }

  if (column.type === "BOOLEAN") {
    return (
      <label className="flex min-h-[32px] cursor-pointer items-center gap-2 px-2 py-1.5">
        <Checkbox
          checked={Boolean(value)}
          onCheckedChange={(checked) => onSave(checked === true)}
          disabled={saving}
        />
        <span className="text-xs text-muted-foreground">{value ? "Yes" : "No"}</span>
      </label>
    )
  }

  if (column.type === "ENUM" && column.options && column.options.length) {
    const opts = column.options
    return (
      <Select
        value={String(value ?? "")}
        onValueChange={(v) => onSave(v)}
        disabled={saving}
      >
        <SelectTrigger className="h-8 gap-1 border-transparent bg-transparent px-2 text-xs shadow-none hover:border-border hover:bg-muted/50">
          {value != null ? (
            <span className={enumPillClasses(String(value), opts)}>
              {String(value)}
            </span>
          ) : (
            <SelectValue placeholder="—" />
          )}
        </SelectTrigger>
        <SelectContent>
          <SelectGroup>
            {opts.map((opt) => (
              <SelectItem key={opt} value={opt}>
                <span className={enumPillClasses(opt, opts)}>{opt}</span>
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    )
  }

  if (editing) {
    const isLong = column.type === "TEXT" && (column.max_length ?? 0) > 200
    const isJson = column.type === "JSON"

    if (isLong || isJson) {
      return (
        <div className="relative min-h-[32px] w-full px-1 py-0.5">
          <Textarea
            ref={inputRef as React.Ref<HTMLTextAreaElement>}
            value={draft}
            onChange={(e) => setDraft(e.target.value)}
            onKeyDown={handleKeyDown}
            onBlur={save}
            rows={3}
            className="min-h-[60px] resize-none border-border bg-background text-sm font-mono placeholder:text-muted-foreground focus-ring"
          />
          {saving && <Loader2 className="absolute right-2 top-2 h-3 w-3 animate-spin text-primary" />}
        </div>
      )
    }

    const inputType = column.type === "INTEGER" || column.type === "FLOAT" || column.type === "SERIAL"
      ? "number"
      : column.type === "DATE"
        ? "date"
        : column.type === "DATETIME"
          ? "datetime-local"
          : "text"

    return (
      <div className="relative min-h-[32px] w-full px-1 py-0.5">
        <Input
          ref={inputRef as React.Ref<HTMLInputElement>}
          type={inputType}
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          onKeyDown={handleKeyDown}
          onBlur={save}
          className="h-8 border-border bg-background text-sm placeholder:text-muted-foreground focus-ring"
        />
        {saving && <Loader2 className="absolute right-2 top-2 h-3 w-3 animate-spin text-primary" />}
      </div>
    )
  }

  return (
    <div
      className="flex min-h-[32px] cursor-pointer items-center rounded-md border border-transparent px-2 py-1.5 text-sm transition-colors hover:border-border hover:bg-muted/50"
      onClick={startEdit}
    >
      {displayValue(value, column, foreignKeyLabelMap)}
    </div>
  )
}

function displayValue(
  value: unknown,
  column: ColumnSchema,
  foreignKeyLabelMap?: Record<string, string>,
): React.ReactNode {
  if (value == null || value === "") return <span className="text-muted-foreground">—</span>
  if (column.foreign_key) {
    const text = String(value)
    return foreignKeyLabelMap?.[text] ?? <span title={text}>{shortenIdentifier(text)}</span>
  }
  if (column.type === "BOOLEAN") return value ? "Yes" : "No"
  if (column.type === "ENUM" && column.options && column.options.length) {
    return <span className={enumPillClasses(String(value), column.options)}>{String(value)}</span>
  }
  if (column.type === "JSON") {
    const str = typeof value === "string" ? value : JSON.stringify(value, null, 2)
    return <span className="font-mono text-xs text-muted-foreground">{str.length > 60 ? str.slice(0, 57) + "…" : str}</span>
  }
  if (column.type === "DATE" || column.type === "DATETIME") {
    try {
      return new Date(String(value)).toLocaleDateString(undefined, { year: "numeric", month: "short", day: "numeric" })
    } catch {
      return String(value)
    }
  }
  if (column.type === "UUID" || (column.foreign_key && column.type === "TEXT")) {
    const s = String(value)
    return <span className="font-mono text-xs text-muted-foreground" title={s}>{shortenIdentifier(s)}</span>
  }
  return String(value)
}

function serialize(value: unknown, type: ColumnSchema["type"]): string {
  if (value == null) return ""
  if (type === "BOOLEAN") return value ? "true" : "false"
  if (type === "JSON") return typeof value === "string" ? value : JSON.stringify(value, null, 2)
  return String(value)
}

function deserialize(raw: string, column: ColumnSchema): unknown {
  const trimmed = raw.trim()
  if (trimmed === "") return null
  if (column.type === "INTEGER" || column.type === "SERIAL") return Number.parseInt(trimmed, 10)
  if (column.type === "FLOAT") return Number.parseFloat(trimmed)
  if (column.type === "BOOLEAN") return trimmed === "true"
  if (column.type === "JSON") {
    try { return JSON.parse(trimmed) } catch { return trimmed }
  }
  return trimmed
}

"use client"

import * as React from "react"
import { Plus, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectGroup, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import type { ColumnSchema, RecordFilter } from "lemma-sdk"

interface FilterBuilderProps {
  columns: ColumnSchema[]
  filters: RecordFilter[]
  onApply: (filters: RecordFilter[]) => void
  onClose: () => void
}

const OPERATORS = [
  { value: "eq", label: "is" },
  { value: "ne", label: "is not" },
  { value: "gt", label: ">" },
  { value: "gte", label: ">=" },
  { value: "lt", label: "<" },
  { value: "lte", label: "<=" },
  { value: "ilike", label: "contains" },
  { value: "starts_with", label: "starts with" },
  { value: "ends_with", label: "ends with" },
  { value: "in", label: "in" },
  { value: "is", label: "is empty" },
  { value: "is not", label: "is not empty" },
] as const

const EMPTY_VALUE = "__lemma_empty__"

function blank(columns: ColumnSchema[]): RecordFilter {
  return { field: columns[0]?.name ?? "", op: "eq", value: "" }
}

export function FilterBuilder({ columns, filters, onApply, onClose }: FilterBuilderProps) {
  const [rows, setRows] = React.useState<RecordFilter[]>(
    filters.length > 0 ? filters : [blank(columns)],
  )

  const update = <K extends keyof RecordFilter>(idx: number, key: K, val: RecordFilter[K]) => {
    setRows((prev) => {
      const next = [...prev]
      next[idx] = { ...next[idx], [key]: val }
      if (key === "field") {
        const col = columns.find((c) => c.name === val)
        if (col?.options?.length) next[idx] = { ...next[idx], op: "eq", value: "" }
      }
      return next
    })
  }

  const remove = (idx: number) => setRows((prev) => prev.filter((_, i) => i !== idx))

  const add = () => setRows((prev) => [...prev, blank(columns)])

  const apply = () => {
    onApply(
      rows.filter(
        (r) =>
          r.field &&
          (r.op === "is" || r.op === "is not" || String(r.value ?? "").trim() !== ""),
      ),
    )
    onClose()
  }

  const inputClass =
    "h-9 w-full rounded-md border border-border bg-background px-3 text-sm text-foreground placeholder:text-muted-foreground hover:border-foreground/20 focus-ring"

  const currentColumn = (field: string) => columns.find((c) => c.name === field)

  return (
    <Dialog open onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="max-w-2xl gap-0 overflow-hidden border-border/60 bg-background p-0">
        <div className="border-b border-border/50 px-6 py-5">
          <DialogHeader>
            <DialogTitle className="text-lg font-semibold tracking-tight">
              Filter Records
            </DialogTitle>
            <DialogDescription className="text-xs uppercase tracking-widest text-muted-foreground">
              Refine your view by adding conditions
            </DialogDescription>
          </DialogHeader>
        </div>

        <div className="max-h-[60vh] space-y-3 overflow-y-auto p-6">
          {rows.map((row, idx) => {
            const col = currentColumn(row.field)
            const needsValue = row.op !== "is" && row.op !== "is not"
            return (
              <div key={idx} className="group flex items-start gap-2">
                <div className="grid flex-1 grid-cols-1 gap-2 md:grid-cols-12">
                  <div className="md:col-span-4">
                    <Select
                      value={row.field}
                      onValueChange={(value) => {
                        if (value != null) update(idx, "field", value)
                      }}
                    >
                      <SelectTrigger className="h-9 w-full">
                        <SelectValue placeholder="Field" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectGroup>
                          {columns.map((c) => (
                            <SelectItem key={c.name} value={c.name}>
                              {c.name}
                            </SelectItem>
                          ))}
                        </SelectGroup>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="md:col-span-3">
                    <Select
                      value={row.op}
                      onValueChange={(value) => {
                        if (value != null) update(idx, "op", value)
                      }}
                    >
                      <SelectTrigger className="h-9 w-full">
                        <SelectValue placeholder="Operator" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectGroup>
                          {OPERATORS.map((o) => (
                            <SelectItem key={o.value} value={o.value}>
                              {o.label}
                            </SelectItem>
                          ))}
                        </SelectGroup>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="md:col-span-5">
                    {needsValue && col?.type === "ENUM" && col.options ? (
                      <Select
                        value={row.value == null || row.value === "" ? EMPTY_VALUE : String(row.value)}
                        onValueChange={(value) => update(idx, "value", value === EMPTY_VALUE ? "" : value)}
                      >
                        <SelectTrigger className="h-9 w-full">
                          <SelectValue placeholder="Value" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            <SelectItem value={EMPTY_VALUE}>—</SelectItem>
                            {col.options.map((opt) => (
                              <SelectItem key={opt} value={opt}>
                                {opt}
                              </SelectItem>
                            ))}
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    ) : needsValue && col?.type === "BOOLEAN" ? (
                      <Select
                        value={row.value == null || row.value === "" ? EMPTY_VALUE : String(row.value)}
                        onValueChange={(value) => update(idx, "value", value === EMPTY_VALUE ? "" : value === "true")}
                      >
                        <SelectTrigger className="h-9 w-full">
                          <SelectValue placeholder="Value" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            <SelectItem value={EMPTY_VALUE}>—</SelectItem>
                            <SelectItem value="true">Yes</SelectItem>
                            <SelectItem value="false">No</SelectItem>
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    ) : needsValue ? (
                      <Input
                        value={String(row.value ?? "")}
                        onChange={(e) => update(idx, "value", e.target.value)}
                        placeholder="Value"
                        className={inputClass}
                      />
                    ) : (
                      <div className={inputClass + " flex items-center text-muted-foreground"}>
                        —
                      </div>
                    )}
                  </div>
                </div>
                <button
                  type="button"
                  onClick={() => remove(idx)}
                  className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-destructive/10 hover:text-destructive"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
              </div>
            )
          })}

          <Button
            variant="ghost"
            size="sm"
            onClick={add}
            className="w-full border border-dashed border-border text-muted-foreground hover:bg-muted/50 hover:text-foreground"
          >
            <Plus className="mr-2 h-4 w-4" />
            Add Condition
          </Button>
        </div>

        <div className="flex items-center justify-end gap-3 border-t border-border/50 bg-muted/30 px-6 py-4">
          <Button variant="ghost" onClick={onClose}>
            Cancel
          </Button>
          <Button onClick={apply}>Apply Filters</Button>
        </div>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import * as React from "react"
import { Calendar, Database, FileText, Link2, RefreshCw, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectGroup, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Textarea } from "@/components/ui/textarea"
import { useForeignKeyOptions, useReferencingRecords, useUpdateRecord } from "lemma-sdk/react"
import type { ColumnSchema, LemmaClient, Table } from "lemma-sdk"
import { cn } from "@/lib/utils"
import { enumPillClasses, isSystemField, typeBadgeClasses } from "./records-enum-utils"
import {
  formatRecordFieldValue,
  pickPrimaryColumn,
  pickSecondaryColumns,
  shortenIdentifier,
} from "./records-display-utils"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
} from "./records-style-utils"

export type RecordDetailVariant = "summary" | "workspace" | "activity"
export type RecordDetailMode = "view" | "editable"
export type RecordDetailTab = "details" | "related" | "activity" | "files"

export interface RecordDetailRelatedRecord {
  tableName: string
  foreignKey: string
  label?: string
  fields?: string[]
  displayField?: string
  subtitleField?: string
  limit?: number
  sortBy?: string
  order?: "asc" | "desc" | string
  onRecordClick?: (record: Record<string, unknown>) => void
}

export interface RecordDetailProps {
  record: Record<string, unknown>
  table: Table
  client: LemmaClient
  podId?: string
  mode?: RecordDetailMode
  variant?: RecordDetailVariant
  tabs?: RecordDetailTab[]
  relatedRecords?: RecordDetailRelatedRecord[]
  hiddenFields?: string[]
  updateVia?: "direct" | "function"
  updateFunctionName?: string
  foreignKeyLabels?: Record<string, string>
  appearance?: LemmaRecordsAppearance
  density?: LemmaRecordsDensity
  radius?: LemmaRecordsRadius
  actions?: React.ReactNode
  className?: string
  onRecordChanged?: () => void
  onDelete?: () => void
}

export function RecordDetail({
  record,
  table,
  client,
  podId,
  mode = "editable",
  variant = "workspace",
  tabs,
  relatedRecords = [],
  hiddenFields = [],
  updateVia,
  updateFunctionName,
  foreignKeyLabels,
  appearance = "default",
  density = "comfortable",
  radius = "lg",
  actions,
  className,
  onRecordChanged,
  onDelete,
}: RecordDetailProps) {
  const primaryKey = table.primary_key_column || "id"
  const recordId = String(record[primaryKey] ?? "")
  const columns = React.useMemo(
    () =>
      table.columns
        .filter((column) => !hiddenFields.includes(column.name))
        .filter((column) => column.type !== "VECTOR"),
    [hiddenFields, table.columns],
  )
  const userColumns = columns.filter((column) => !isSystemField(column))
  const systemColumns = columns.filter((column) => isSystemField(column))
  const primaryColumn = pickPrimaryColumn(userColumns)
  const secondaryColumns = pickSecondaryColumns(userColumns, primaryColumn, { count: 3 })
  const title = formatPlainValue(primaryColumn ? record[primaryColumn.name] : undefined) || "Untitled record"
  const activeTabs = React.useMemo(() => {
    const requested = tabs?.length ? tabs : relatedRecords.length ? ["details", "related", "activity"] : ["details", "activity"]
    return requested.filter((tab, index, allTabs) => allTabs.indexOf(tab) === index)
  }, [relatedRecords.length, tabs])
  const defaultTab = activeTabs[0] ?? "details"

  return (
    <section
      data-appearance={appearance}
      data-density={density}
      data-radius={radius}
      className={cn(
        "lemma-record-detail min-h-0 overflow-hidden",
        detailSurfaceClassName(appearance, radius),
        className,
      )}
    >
      <div className={cn("flex flex-col", density === "compact" ? "gap-3 p-4" : density === "spacious" ? "gap-5 p-7" : "gap-4 p-6")}>
        <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
          <div className="flex min-w-0 items-start gap-3">
            <div className={cn("flex shrink-0 items-center justify-center border border-border/50 bg-muted/35 text-muted-foreground", recordsRadiusClassName(radius, "control"), density === "compact" ? "size-9" : "size-10")}>
              <Database className="size-4" />
            </div>
            <div className="min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <h2 className={cn("truncate font-semibold tracking-tight text-foreground", density === "compact" ? "text-lg" : "text-xl")}>
                  {title}
                </h2>
                <span className={cn("inline-flex items-center border border-border/50 bg-muted/40 px-2 py-0.5 font-mono text-[11px] text-muted-foreground", recordsRadiusClassName(radius, "pill"))}>
                  {shortenIdentifier(recordId)}
                </span>
              </div>
              <div className="mt-2 flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
                <span>{table.name}</span>
                {secondaryColumns.map((column) => {
                  const value = record[column.name]
                  if (value == null || value === "") return null
                  return (
                    <span key={column.name} className={cn("inline-flex max-w-64 items-center gap-1 truncate bg-muted/35 px-2 py-0.5", recordsRadiusClassName(radius, "pill"))}>
                      <span className="text-muted-foreground/75">{column.name.replace(/_/g, " ")}</span>
                      <span className="truncate text-foreground">{formatRecordFieldValue(value, column)}</span>
                    </span>
                  )
                })}
              </div>
            </div>
          </div>
          <div className="flex shrink-0 items-center gap-2">
            {actions}
            {onDelete ? (
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="text-destructive hover:bg-destructive/10 hover:text-destructive"
                onClick={onDelete}
              >
                <Trash2 data-icon="inline-start" />
                Delete
              </Button>
            ) : null}
          </div>
        </div>

        <Tabs defaultValue={defaultTab} className="min-h-0">
          {activeTabs.length > 1 ? (
            <TabsList className={cn("w-full justify-start", recordsRadiusClassName(radius, "control"))}>
              {activeTabs.map((tab) => (
                <TabsTrigger key={tab} value={tab} className="capitalize">
                  {tab}
                </TabsTrigger>
              ))}
            </TabsList>
          ) : null}

          {activeTabs.includes("details") ? (
            <TabsContent value="details" className="mt-4">
              <DetailsTab
                record={record}
                columns={userColumns}
                client={client}
                podId={podId}
                tableName={table.name}
                recordId={recordId}
                mode={mode}
                variant={variant}
                updateVia={updateVia}
                updateFunctionName={updateFunctionName}
                foreignKeyLabels={foreignKeyLabels}
                density={density}
                radius={radius}
                onRecordChanged={onRecordChanged}
              />
            </TabsContent>
          ) : null}

          {activeTabs.includes("related") ? (
            <TabsContent value="related" className="mt-4">
              <RelatedTab
                recordId={recordId}
                configs={relatedRecords}
                client={client}
                podId={podId}
                appearance={appearance}
                density={density}
                radius={radius}
              />
            </TabsContent>
          ) : null}

          {activeTabs.includes("activity") ? (
            <TabsContent value="activity" className="mt-4">
              <ActivityTab record={record} columns={systemColumns} appearance={appearance} density={density} radius={radius} />
            </TabsContent>
          ) : null}

          {activeTabs.includes("files") ? (
            <TabsContent value="files" className="mt-4">
              <EmptyDetailState
                icon={FileText}
                title="Files are ready to attach"
                description="This slot is designed for the upcoming file and folder components so records can show contracts, decks, notes, and email attachments in context."
                appearance={appearance}
                radius={radius}
              />
            </TabsContent>
          ) : null}
        </Tabs>
      </div>
    </section>
  )
}

function DetailsTab({
  record,
  columns,
  client,
  podId,
  tableName,
  recordId,
  mode,
  variant,
  updateVia,
  updateFunctionName,
  foreignKeyLabels,
  density,
  radius,
  onRecordChanged,
}: {
  record: Record<string, unknown>
  columns: ColumnSchema[]
  client: LemmaClient
  podId?: string
  tableName: string
  recordId: string
  mode: RecordDetailMode
  variant: RecordDetailVariant
  updateVia?: "direct" | "function"
  updateFunctionName?: string
  foreignKeyLabels?: Record<string, string>
  density: LemmaRecordsDensity
  radius: LemmaRecordsRadius
  onRecordChanged?: () => void
}) {
  const fieldColumns = columns.filter((column) => column.name !== "id" && column.name !== "sort_order")
  const gridClassName = variant === "summary"
    ? "grid-cols-1"
    : "grid-cols-1 xl:grid-cols-2"

  return (
    <div className={cn("grid", gridClassName, density === "compact" ? "gap-2" : density === "spacious" ? "gap-4" : "gap-3")}>
      {fieldColumns.map((column) => (
        <RecordField
          key={column.name}
          record={record}
          column={column}
          client={client}
          podId={podId}
          tableName={tableName}
          recordId={recordId}
          mode={mode}
          updateVia={updateVia}
          updateFunctionName={updateFunctionName}
          foreignKeyLabels={foreignKeyLabels}
          density={density}
          radius={radius}
          onRecordChanged={onRecordChanged}
        />
      ))}
    </div>
  )
}

function RecordField({
  record,
  column,
  client,
  podId,
  tableName,
  recordId,
  mode,
  updateVia,
  updateFunctionName,
  foreignKeyLabels,
  density,
  radius,
  onRecordChanged,
}: {
  record: Record<string, unknown>
  column: ColumnSchema
  client: LemmaClient
  podId?: string
  tableName: string
  recordId: string
  mode: RecordDetailMode
  updateVia?: "direct" | "function"
  updateFunctionName?: string
  foreignKeyLabels?: Record<string, string>
  density: LemmaRecordsDensity
  radius: LemmaRecordsRadius
  onRecordChanged?: () => void
}) {
  const value = record[column.name]
  const updateMutation = useUpdateRecord({ client, podId, tableName, recordId, updateVia, updateFunctionName })
  const save = async (nextValue: unknown) => {
    await updateMutation.update({ [column.name]: nextValue })
    onRecordChanged?.()
  }

  return (
    <div className={cn("group border border-border/40 bg-muted/15", recordsRadiusClassName(radius, "surface"), density === "compact" ? "p-3" : density === "spacious" ? "p-4" : "p-3.5")}>
      <div className="mb-2 flex items-center gap-2">
        <p className="truncate text-[10px] font-semibold uppercase tracking-widest text-muted-foreground">
          {column.name.replace(/_/g, " ")}
        </p>
        <span className={typeBadgeClasses(column)}>
          {column.foreign_key ? "ref" : column.type.toLowerCase()}
        </span>
      </div>
      {mode === "editable" ? (
        <EditableFieldValue
          value={value}
          column={column}
          client={client}
          podId={podId}
          tableName={tableName}
          labelField={foreignKeyLabels?.[column.name]}
          radius={radius}
          disabled={updateMutation.isSubmitting}
          onSave={save}
        />
      ) : (
        <ReadOnlyFieldValue
          value={value}
          column={column}
          client={client}
          podId={podId}
          tableName={tableName}
          labelField={foreignKeyLabels?.[column.name]}
          radius={radius}
        />
      )}
      {updateMutation.error ? (
        <p className="mt-2 text-xs text-destructive">{updateMutation.error.message}</p>
      ) : null}
    </div>
  )
}

function ReadOnlyFieldValue({
  value,
  column,
  client,
  podId,
  tableName,
  labelField,
  radius,
}: {
  value: unknown
  column: ColumnSchema
  client: LemmaClient
  podId?: string
  tableName: string
  labelField?: string
  radius: LemmaRecordsRadius
}) {
  const fkOptions = useForeignKeyOptions({
    client,
    podId,
    tableName,
    columnName: column.name,
    labelField,
    enabled: !!column.foreign_key,
  })
  const resolvedLabel = fkOptions.options.find((option) => String(option.value) === String(value))?.label

  if (value == null || value === "") return <p className="text-sm italic text-muted-foreground">Empty</p>
  if (column.foreign_key) return <p className="truncate text-sm font-medium text-foreground">{resolvedLabel ?? shortenIdentifier(value)}</p>
  if (column.type === "JSON") {
    const text = typeof value === "string" ? value : JSON.stringify(value, null, 2)
    return (
      <pre className={cn("max-h-48 overflow-auto border border-border/40 bg-background/60 p-3 font-mono text-xs text-foreground", recordsRadiusClassName(radius, "control"))}>
        {text}
      </pre>
    )
  }
  if (column.type === "DATE" || column.type === "DATETIME") {
    return (
      <p className="flex items-center gap-1.5 text-sm text-foreground">
        <Calendar className="size-3.5 text-muted-foreground" />
        {formatTimestamp(value)}
      </p>
    )
  }
  return <div className="break-words text-sm text-foreground">{formatRecordFieldValue(value, column)}</div>
}

function EditableFieldValue({
  value,
  column,
  client,
  podId,
  tableName,
  labelField,
  radius,
  disabled,
  onSave,
}: {
  value: unknown
  column: ColumnSchema
  client: LemmaClient
  podId?: string
  tableName: string
  labelField?: string
  radius: LemmaRecordsRadius
  disabled?: boolean
  onSave: (value: unknown) => Promise<void>
}) {
  const [draft, setDraft] = React.useState(value == null ? "" : String(value))
  const fkOptions = useForeignKeyOptions({
    client,
    podId,
    tableName,
    columnName: column.name,
    labelField,
    enabled: !!column.foreign_key,
  })

  React.useEffect(() => {
    setDraft(value == null ? "" : String(value))
  }, [value])

  const controlClassName = cn("border-border/70 bg-background/70", recordsRadiusClassName(radius, "control"))

  if (column.foreign_key) {
    const selectedLabel = fkOptions.options.find((option) => String(option.value) === draft)?.label
    return (
      <Select value={draft} onValueChange={(nextValue) => void onSave(nextValue)} disabled={disabled}>
        <SelectTrigger className={cn("h-8", controlClassName)}>
          <SelectValue placeholder="Select...">
            {selectedLabel ?? (draft ? shortenIdentifier(draft) : undefined)}
          </SelectValue>
        </SelectTrigger>
        <SelectContent>
          <SelectGroup>
            {fkOptions.options.map((option) => (
              <SelectItem key={String(option.value)} value={String(option.value)}>
                {option.label}
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    )
  }

  if (column.type === "ENUM" && column.options?.length) {
    return (
      <Select value={draft || undefined} onValueChange={(nextValue) => void onSave(nextValue)} disabled={disabled}>
        <SelectTrigger className={cn("h-8", controlClassName)}>
          <SelectValue placeholder="Select..." />
        </SelectTrigger>
        <SelectContent>
          <SelectGroup>
            {column.options.map((option) => (
              <SelectItem key={option} value={option}>
                <span className={enumPillClasses(option, column.options!)}>{option}</span>
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    )
  }

  if (column.type === "BOOLEAN") {
    const checked = draft === "true" || draft === "1"
    return (
      <Button
        type="button"
        variant="outline"
        size="sm"
        className={cn("h-8 justify-start", controlClassName)}
        disabled={disabled}
        onClick={() => void onSave(!checked)}
      >
        {checked ? "Yes" : "No"}
      </Button>
    )
  }

  if (column.type === "JSON") {
    return (
      <Textarea
        value={draft}
        rows={5}
        disabled={disabled}
        className={cn("font-mono text-xs", controlClassName)}
        onChange={(event) => setDraft(event.target.value)}
        onBlur={() => void onSave(parseJsonDraft(draft))}
      />
    )
  }

  if (column.type === "DATE" || column.type === "DATETIME") {
    return (
      <Input
        type={column.type === "DATE" ? "date" : "datetime-local"}
        value={draft}
        disabled={disabled}
        className={cn("h-8", controlClassName)}
        onChange={(event) => setDraft(event.target.value)}
        onBlur={() => void onSave(draft || null)}
      />
    )
  }

  return (
    <Input
      value={draft}
      type={column.type === "INTEGER" || column.type === "FLOAT" ? "number" : "text"}
      disabled={disabled}
      className={cn("h-8", controlClassName)}
      onChange={(event) => setDraft(event.target.value)}
      onBlur={() => void onSave(coerceDraftValue(draft, column))}
      onKeyDown={(event) => {
        if (event.key === "Enter") {
          event.currentTarget.blur()
        }
      }}
    />
  )
}

function RelatedTab({
  recordId,
  configs,
  client,
  podId,
  appearance,
  density,
  radius,
}: {
  recordId: string
  configs: RecordDetailRelatedRecord[]
  client: LemmaClient
  podId?: string
  appearance: LemmaRecordsAppearance
  density: LemmaRecordsDensity
  radius: LemmaRecordsRadius
}) {
  if (configs.length === 0) {
    return (
      <EmptyDetailState
        icon={Link2}
        title="No related sections configured"
        description="Pass relatedRecords to show child tables like tasks, comments, emails, notes, line items, or activity history for this record."
        appearance={appearance}
        radius={radius}
      />
    )
  }

  return (
    <div className={cn("grid grid-cols-1", density === "compact" ? "gap-2" : density === "spacious" ? "gap-4" : "gap-3")}>
      {configs.map((config) => (
        <RelatedRecordsPanel
          key={`${config.tableName}:${config.foreignKey}`}
          recordId={recordId}
          config={config}
          client={client}
          podId={podId}
          appearance={appearance}
          radius={radius}
        />
      ))}
    </div>
  )
}

function RelatedRecordsPanel({
  recordId,
  config,
  client,
  podId,
  appearance,
  radius,
}: {
  recordId: string
  config: RecordDetailRelatedRecord
  client: LemmaClient
  podId?: string
  appearance: LemmaRecordsAppearance
  radius: LemmaRecordsRadius
}) {
  const related = useReferencingRecords({
    client,
    podId,
    table: config.tableName,
    foreignKey: config.foreignKey,
    recordId,
    fields: config.fields,
    limit: config.limit ?? 8,
    sortBy: config.sortBy,
    order: config.order,
  })
  const table = related.referencedTable
  const primaryColumn = table
    ? table.columns.find((column) => column.name === config.displayField) ?? pickPrimaryColumn(table.columns)
    : undefined
  const subtitleColumn = table && config.subtitleField
    ? table.columns.find((column) => column.name === config.subtitleField)
    : undefined

  return (
    <div className={cn("border border-border/40", relatedPanelClassName(appearance), recordsRadiusClassName(radius, "surface"))}>
      <div className="flex items-center justify-between gap-3 border-b border-border/25 px-3 py-2.5">
        <div className="min-w-0">
          <p className="truncate text-sm font-medium text-foreground">{config.label ?? sentenceCase(config.tableName)}</p>
          <p className="text-xs text-muted-foreground">{config.foreignKey} links back to this record</p>
        </div>
        <span className={cn("shrink-0 bg-muted/50 px-2 py-0.5 text-xs text-muted-foreground", recordsRadiusClassName(radius, "pill"))}>
          {related.isLoading ? "..." : related.total}
        </span>
      </div>
      <div className="p-2">
        {related.isLoading ? (
          <div className="flex items-center gap-2 px-2 py-3 text-sm text-muted-foreground">
            <RefreshCw className="size-4 animate-spin" />
            Loading related records...
          </div>
        ) : related.error ? (
          <p className="px-2 py-3 text-sm text-destructive">{related.error.message}</p>
        ) : related.records.length === 0 ? (
          <p className="px-2 py-3 text-sm text-muted-foreground">No related records yet.</p>
        ) : (
          <div className="flex flex-col gap-1">
            {related.records.map((childRecord, index) => {
              const title = formatPlainValue(primaryColumn ? childRecord[primaryColumn.name] : undefined) || "Untitled"
              const subtitle = subtitleColumn ? formatPlainValue(childRecord[subtitleColumn.name]) : null
              return (
                <button
                  key={String(childRecord.id ?? index)}
                  type="button"
                  className={cn(
                    "flex w-full items-start justify-between gap-3 px-3 py-2 text-left transition-colors hover:bg-muted/45",
                    recordsRadiusClassName(radius, "control"),
                  )}
                  onClick={() => config.onRecordClick?.(childRecord)}
                >
                  <span className="min-w-0">
                    <span className="block truncate text-sm font-medium text-foreground">{title}</span>
                    {subtitle ? <span className="mt-0.5 block truncate text-xs text-muted-foreground">{subtitle}</span> : null}
                  </span>
                  <span className="shrink-0 text-xs text-muted-foreground">{shortenIdentifier(childRecord.id ?? index)}</span>
                </button>
              )
            })}
          </div>
        )}
      </div>
    </div>
  )
}

function ActivityTab({
  record,
  columns,
  appearance,
  density,
  radius,
}: {
  record: Record<string, unknown>
  columns: ColumnSchema[]
  appearance: LemmaRecordsAppearance
  density: LemmaRecordsDensity
  radius: LemmaRecordsRadius
}) {
  const events = columns
    .filter((column) => column.name === "created_at" || column.name === "updated_at" || /activity|contacted|closed|sent|received/i.test(column.name))
    .map((column) => ({
      key: column.name,
      label: sentenceCase(column.name),
      value: record[column.name],
    }))
    .filter((event) => event.value != null && event.value !== "")

  if (events.length === 0) {
    return (
      <EmptyDetailState
        icon={Calendar}
        title="No activity timeline yet"
        description="Timestamp fields, comments, emails, workflow runs, and audit events can all land here as the pod schema grows."
        appearance={appearance}
        radius={radius}
      />
    )
  }

  return (
    <div className={cn("relative flex flex-col", density === "compact" ? "gap-2" : "gap-3")}>
      {events.map((event, index) => (
        <div key={event.key} className="grid grid-cols-[auto_minmax(0,1fr)] gap-3">
          <div className="flex flex-col items-center">
            <span className={cn("flex size-7 items-center justify-center border border-border/50 bg-muted/40 text-muted-foreground", recordsRadiusClassName(radius, "pill"))}>
              <Calendar className="size-3.5" />
            </span>
            {index < events.length - 1 ? <span className="my-1 h-full min-h-4 w-px bg-border/50" /> : null}
          </div>
          <div className={cn("border border-border/40 bg-muted/15 p-3", recordsRadiusClassName(radius, "surface"))}>
            <p className="text-sm font-medium text-foreground">{event.label}</p>
            <p className="mt-1 text-sm text-muted-foreground">{formatTimestamp(event.value)}</p>
          </div>
        </div>
      ))}
    </div>
  )
}

function EmptyDetailState({
  title,
  description,
  icon: Icon,
  appearance,
  radius,
}: {
  title: string
  description: string
  icon: React.ComponentType<{ className?: string }>
  appearance: LemmaRecordsAppearance
  radius: LemmaRecordsRadius
}) {
  return (
    <div className={cn("flex min-h-48 flex-col items-center justify-center gap-3 border border-dashed border-border/40 px-6 py-8 text-center", appearance === "minimal" ? "bg-transparent" : "bg-muted/15", recordsRadiusClassName(radius, "surface"))}>
      <div className={cn("flex size-10 items-center justify-center border border-border/50 bg-muted/35 text-muted-foreground", recordsRadiusClassName(radius, "pill"))}>
        <Icon className="size-4" />
      </div>
      <div>
        <p className="font-medium text-foreground">{title}</p>
        <p className="mt-1 max-w-md text-sm text-muted-foreground">{description}</p>
      </div>
    </div>
  )
}

function detailSurfaceClassName(appearance: LemmaRecordsAppearance, radius: LemmaRecordsRadius) {
  return cn(
    recordsRadiusClassName(radius, "surface"),
    appearance === "minimal" ? "bg-transparent" : "bg-card",
    appearance === "borderless" || appearance === "minimal" ? "border-0 shadow-none" : "border border-border/50 shadow-sm",
    appearance === "contained" && "border-border/70 bg-card",
  )
}

function relatedPanelClassName(appearance: LemmaRecordsAppearance) {
  if (appearance === "minimal" || appearance === "borderless") return "bg-transparent"
  return "bg-card/80"
}

function formatPlainValue(value: unknown): string {
  if (value == null || value === "") return ""
  if (value instanceof Date) return formatTimestamp(value)
  if (typeof value === "object") return JSON.stringify(value)
  return String(value)
}

function formatTimestamp(value: unknown): string {
  if (value == null || value === "") return "—"
  const date = value instanceof Date ? value : new Date(String(value))
  if (Number.isNaN(date.getTime())) return String(value)
  return date.toLocaleDateString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  })
}

function sentenceCase(value: string): string {
  return value
    .replace(/[_\.]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase())
}

function coerceDraftValue(value: string, column: ColumnSchema): unknown {
  if (value === "") return null
  if (column.type === "INTEGER") return Number.parseInt(value, 10)
  if (column.type === "FLOAT") return Number.parseFloat(value)
  return value
}

function parseJsonDraft(value: string): unknown {
  if (!value.trim()) return null
  try {
    return JSON.parse(value)
  } catch {
    return value
  }
}

"use client"

import * as React from "react"
import { ChevronLeft, ChevronRight } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Dialog, DialogContent } from "@/components/ui/dialog"
import { Sheet, SheetContent } from "@/components/ui/sheet"
import type { LemmaClient, Table } from "lemma-sdk"
import { cn } from "@/lib/utils"
import {
  RecordDetail,
  type RecordDetailRelatedRecord,
  type RecordDetailTab,
  type RecordDetailVariant,
} from "./records-detail"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
} from "./records-style-utils"

export interface DetailSheetProps {
  record: Record<string, unknown>
  table: Table
  client: LemmaClient
  podId?: string
  mode?: "sheet" | "modal"
  variant?: RecordDetailVariant
  tabs?: RecordDetailTab[]
  relatedRecords?: RecordDetailRelatedRecord[]
  editable?: boolean
  hiddenFields?: string[]
  onClose: () => void
  onRecordChanged: () => void
  onDelete: () => void
  onNext?: () => void
  onPrevious?: () => void
  hasPrevious?: boolean
  hasNext?: boolean
  updateVia?: "direct" | "function"
  updateFunctionName?: string
  foreignKeyLabels?: Record<string, string>
  appearance?: LemmaRecordsAppearance
  density?: LemmaRecordsDensity
  radius?: LemmaRecordsRadius
}

export function DetailSheet({
  record,
  table,
  client,
  podId,
  mode = "sheet",
  variant = "workspace",
  tabs,
  relatedRecords,
  editable = true,
  hiddenFields,
  onClose,
  onRecordChanged,
  onDelete,
  onNext,
  onPrevious,
  hasPrevious,
  hasNext,
  updateVia,
  updateFunctionName,
  foreignKeyLabels,
  appearance = "default",
  density = "comfortable",
  radius = "lg",
}: DetailSheetProps) {
  const content = (
    <RecordDetail
      record={record}
      table={table}
      client={client}
      podId={podId}
      mode={editable ? "editable" : "view"}
      variant={variant}
      tabs={tabs}
      relatedRecords={relatedRecords}
      hiddenFields={hiddenFields}
      updateVia={updateVia}
      updateFunctionName={updateFunctionName}
      foreignKeyLabels={foreignKeyLabels}
      appearance={appearance}
      density={density}
      radius={radius}
      onRecordChanged={onRecordChanged}
      onDelete={onDelete}
      className="h-full overflow-y-auto border-0 shadow-none"
      actions={
        <div className="flex items-center gap-1">
          <Button
            type="button"
            variant="ghost"
            size="icon-sm"
            onClick={onPrevious}
            disabled={!hasPrevious}
          >
            <ChevronLeft />
            <span className="sr-only">Previous record</span>
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon-sm"
            onClick={onNext}
            disabled={!hasNext}
          >
            <ChevronRight />
            <span className="sr-only">Next record</span>
          </Button>
        </div>
      }
    />
  )

  if (mode === "modal") {
    return (
      <Dialog open onOpenChange={(open) => !open && onClose()}>
        <DialogContent
          className={cn(
            "max-h-[88vh] max-w-4xl gap-0 overflow-hidden p-0",
            detailOverlayClassName(appearance, radius),
          )}
        >
          {content}
        </DialogContent>
      </Dialog>
    )
  }

  return (
    <Sheet open onOpenChange={(open) => !open && onClose()}>
      <SheetContent
        className={cn(
          "w-full gap-0 overflow-hidden p-0 sm:max-w-2xl",
          detailOverlayClassName(appearance, radius),
        )}
      >
        {content}
      </SheetContent>
    </Sheet>
  )
}
function detailOverlayClassName(appearance: LemmaRecordsAppearance, radius: LemmaRecordsRadius) {
  return cn(
    recordsRadiusClassName(radius, "overlay"),
    appearance === "minimal" ? "border-0 bg-background shadow-none" : null,
    appearance === "borderless" ? "border-0 bg-background shadow-xl" : null,
    appearance === "contained" ? "border-border/70 bg-card shadow-xl" : null,
    appearance === "default" ? "border-border/50 bg-card" : null,
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { Card, CardContent } from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import type { ColumnSchema, Table } from "lemma-sdk"
import { isSystemField } from "./records-enum-utils"
import {
  formatRecordFieldValue,
  pickPrimaryColumn,
  pickSecondaryColumns,
  type ForeignKeyLabelMap,
} from "./records-display-utils"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
} from "./records-style-utils"

interface ListViewProps {
  records: Record<string, unknown>[]
  table: Table
  visibleColumns?: ColumnSchema[]
  appearance?: LemmaRecordsAppearance
  density?: LemmaRecordsDensity
  radius?: LemmaRecordsRadius
  selectedRecords: Set<string>
  onSelectRecord: (id: string) => void
  onRecordClick: (record: Record<string, unknown>) => void
  renderCard?: (record: Record<string, unknown>, columns: ColumnSchema[]) => React.ReactNode
  foreignKeyLabelMap?: ForeignKeyLabelMap
}

export function ListView({
  records,
  table,
  visibleColumns,
  selectedRecords,
  onSelectRecord,
  onRecordClick,
  renderCard,
  foreignKeyLabelMap,
  appearance = "default",
  density = "comfortable",
  radius = "lg",
}: ListViewProps) {
  const pk = table.primary_key_column || "id"
  const columns = visibleColumns ?? table.columns.filter((c) => !isSystemField(c))

  const primaryCol = pickPrimaryColumn(columns)
  const secondaryCols = pickSecondaryColumns(columns, primaryCol, { count: 5 })

  return (
    <div className={cn("flex flex-col", density === "compact" ? "gap-1.5" : density === "spacious" ? "gap-3" : "gap-2")}>
      {records.map((record) => {
        const id = String(record[pk] ?? "")
        const selected = selectedRecords.has(id)
        return (
          <Card
            key={id}
            size="sm"
            onClick={() => onRecordClick(record)}
            className={cn(
              "cursor-pointer transition-colors",
              selected
                ? "bg-primary/5 ring-primary/35"
                : "hover:bg-muted/30 hover:ring-foreground/20",
              appearance === "borderless" && "ring-0 shadow-none",
              appearance === "minimal" && (
                selected
                  ? "shadow-none ring-primary/25"
                  : "bg-transparent shadow-none ring-0 hover:bg-muted/30"
              ),
              recordsRadiusClassName(radius, "surface"),
            )}
          >
            {renderCard ? (
              <CardContent>{renderCard(record, columns)}</CardContent>
            ) : (
              <CardContent className={cn("flex items-start gap-3", density === "compact" ? "py-2" : density === "spacious" ? "py-4" : null)}>
                <Checkbox
                  checked={selected}
                  onCheckedChange={() => onSelectRecord(id)}
                  onClick={(e) => e.stopPropagation()}
                  className="mt-1"
                />
                <div className="min-w-0 flex-1">
                  <p className="font-medium text-sm text-foreground truncate">
                    {formatRecordFieldValue(primaryCol ? record[primaryCol.name] : undefined, primaryCol, foreignKeyLabelMap)}
                  </p>
                  <div className="mt-1.5 flex flex-wrap items-center gap-x-3 gap-y-1">
                    {secondaryCols.map((col) => {
                      const val = record[col.name]
                      if (val == null || val === "") return null
                      return (
                        <span key={col.name} className="text-xs text-muted-foreground">
                          <span className="font-medium">{col.name.replace(/_/g, " ")}:</span>{" "}
                          {formatRecordFieldValue(val, col, foreignKeyLabelMap)}
                        </span>
                      )
                    })}
                  </div>
                </div>
              </CardContent>
            )}
          </Card>
        )
      })}
    </div>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { Card, CardContent } from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import type { ColumnSchema } from "lemma-sdk"
import { enumPillClasses } from "./records-enum-utils"
import {
  formatRecordFieldValue,
  pickPrimaryColumn,
  pickSecondaryColumns,
  type ForeignKeyLabelMap,
} from "./records-display-utils"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
} from "./records-style-utils"

interface GroupedViewProps {
  records: Record<string, unknown>[]
  groupByColumn: ColumnSchema
  layout?: "kanban" | "linear"
  appearance?: LemmaRecordsAppearance
  density?: LemmaRecordsDensity
  radius?: LemmaRecordsRadius
  primaryKey: string
  visibleColumns: ColumnSchema[]
  selectedRecords: Set<string>
  onSelectRecord: (id: string) => void
  onRecordClick: (record: Record<string, unknown>) => void
  renderCard?: (record: Record<string, unknown>, columns: ColumnSchema[]) => React.ReactNode
  foreignKeyLabelMap?: ForeignKeyLabelMap
}

export function GroupedView({
  records,
  groupByColumn,
  layout = "kanban",
  appearance = "default",
  density = "comfortable",
  radius = "lg",
  primaryKey,
  visibleColumns,
  selectedRecords,
  onSelectRecord,
  onRecordClick,
  renderCard,
  foreignKeyLabelMap,
}: GroupedViewProps) {
  const groups = React.useMemo(() => {
    const map = new Map<string, Record<string, unknown>[]>()
    const ungrouped: Record<string, unknown>[] = []

    for (const rec of records) {
      const key = rec[groupByColumn.name]
      if (key == null || key === "") {
        ungrouped.push(rec)
      } else {
        const k = String(key)
        if (!map.has(k)) map.set(k, [])
        map.get(k)!.push(rec)
      }
    }

    const entries: Array<{ label: string; records: Record<string, unknown>[] }> = []
    if (groupByColumn.options?.length) {
      for (const opt of groupByColumn.options) {
        entries.push({ label: opt, records: map.get(opt) ?? [] })
        map.delete(opt)
      }
    }
    for (const [k, recs] of map) {
      entries.push({ label: k, records: recs })
    }
    if (ungrouped.length) {
      entries.push({ label: "Ungrouped", records: ungrouped })
    }

    return entries
  }, [records, groupByColumn])

  const primaryCol = pickPrimaryColumn(visibleColumns)
  const secondaryCols = pickSecondaryColumns(visibleColumns, primaryCol, {
    groupBy: groupByColumn.name,
    count: layout === "kanban" ? 4 : 5,
  })

  const groupClass = layout === "kanban"
    ? cn("flex min-w-max pb-2", density === "compact" ? "gap-2" : density === "spacious" ? "gap-4" : "gap-3")
    : cn("flex min-w-0 flex-col", density === "compact" ? "gap-2" : density === "spacious" ? "gap-4" : "gap-3")

  const sectionClass = layout === "kanban"
    ? cn(
        "flex max-h-full shrink-0 flex-col",
        recordsRadiusClassName(radius, "surface"),
        density === "compact" ? "w-72" : density === "spacious" ? "w-96" : "w-80",
        appearance === "minimal"
          ? "border-0 bg-transparent"
          : appearance === "borderless"
            ? "border-0 bg-muted/10"
            : "border border-border/50 bg-muted/20",
      )
    : cn(
        "flex min-w-0 flex-col",
        recordsRadiusClassName(radius, "surface"),
        appearance === "minimal"
          ? "border-0 bg-transparent"
          : appearance === "borderless"
            ? "border-0 bg-transparent"
            : "border border-border/50 bg-card",
      )

  return (
    <div className={groupClass}>
      {groups.map((group) => (
        <section
          key={group.label}
          className={sectionClass}
        >
          <div className={cn("flex items-center justify-between gap-3 px-3", appearance === "borderless" ? "border-b-0" : appearance === "minimal" ? "border-b border-border/15" : "border-b border-border/40", density === "compact" ? "py-2" : density === "spacious" ? "py-3" : "py-2.5")}>
            {groupByColumn.options?.length ? (
              <span className={enumPillClasses(group.label, groupByColumn.options)}>
                {group.label}
              </span>
            ) : (
              <span className={cn("inline-flex items-center border border-border/50 bg-muted/50 px-2.5 py-1 text-xs font-medium text-foreground", recordsRadiusClassName(radius, "pill"))}>
                {group.label}
              </span>
            )}
            <span className={cn("bg-background px-2 py-0.5 text-xs text-muted-foreground ring-1 ring-border/50", recordsRadiusClassName(radius, "pill"))}>
              {group.records.length}
            </span>
          </div>
          <div className={cn("flex flex-col", density === "compact" ? "gap-1.5 p-1.5" : density === "spacious" ? "gap-3 p-3" : "gap-2 p-2", layout === "kanban" && "overflow-y-auto")}>
            {group.records.length === 0 && (
              <div className={cn("px-3 py-6 text-center text-xs text-muted-foreground", recordsRadiusClassName(radius, "surface"), appearance === "minimal" ? "border border-dashed border-border/25 bg-transparent" : "border border-dashed border-border/60 bg-background/40")}>
                No records
              </div>
            )}
            {group.records.map((record) => {
              const id = String(record[primaryKey] ?? "")
              const selected = selectedRecords.has(id)
              if (renderCard) {
                return (
                  <Card
                    key={id}
                    size="sm"
                    onClick={() => onRecordClick(record)}
                    className={cn(
                      "cursor-pointer transition-colors",
                      selected ? "bg-primary/5 ring-primary/35" : "hover:bg-background hover:ring-foreground/20",
                      appearance === "borderless" && "ring-0 shadow-none",
                      appearance === "minimal" && (
                        selected
                          ? "shadow-none ring-primary/25"
                          : "bg-transparent shadow-none ring-0 hover:bg-muted/30"
                      ),
                      recordsRadiusClassName(radius, "surface"),
                    )}
                  >
                    <CardContent>{renderCard(record, visibleColumns)}</CardContent>
                  </Card>
                )
              }
              return (
                <Card
                  key={id}
                  size="sm"
                  onClick={() => onRecordClick(record)}
                  className={cn(
                    "cursor-pointer transition-colors",
                    selected ? "bg-primary/5 ring-primary/35" : "hover:bg-background hover:ring-foreground/20",
                    appearance === "borderless" && "ring-0 shadow-none",
                    appearance === "minimal" && (
                      selected
                        ? "shadow-none ring-primary/25"
                        : "bg-transparent shadow-none ring-0 hover:bg-muted/30"
                    ),
                    recordsRadiusClassName(radius, "surface"),
                  )}
                >
                  <CardContent className={cn("flex gap-2", layout === "kanban" ? "flex-col" : "items-center", density === "compact" ? "py-2" : density === "spacious" ? "py-4" : null)}>
                    <div className="flex min-w-0 flex-1 items-start gap-2">
                      <Checkbox
                        checked={selected}
                        onCheckedChange={() => onSelectRecord(id)}
                        onClick={(e) => e.stopPropagation()}
                        className="mt-0.5"
                      />
                      <span className="min-w-0 flex-1 truncate text-sm font-medium text-foreground">
                        {formatRecordFieldValue(primaryCol ? record[primaryCol.name] : undefined, primaryCol, foreignKeyLabelMap)}
                      </span>
                    </div>
                    <div className={cn("flex flex-wrap gap-1.5", layout === "kanban" ? "pl-6" : "justify-end")}>
                      {secondaryCols.map((col) => {
                        const v = record[col.name]
                        if (v == null || v === "") return null
                        return (
                          <span
                            key={col.name}
                            className={cn("max-w-full truncate bg-muted/50 px-1.5 py-0.5 text-xs text-muted-foreground", recordsRadiusClassName(radius, "control"))}
                          >
                            {formatRecordFieldValue(v, col, foreignKeyLabelMap)}
                          </span>
                        )
                      })}
                    </div>
                  </CardContent>
                </Card>
              )
            })}
          </div>
        </section>
      ))}
    </div>
  )
}

"use client"

import * as React from "react"
import { Loader2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Checkbox } from "@/components/ui/checkbox"
import { Label } from "@/components/ui/label"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Sheet, SheetContent, SheetDescription, SheetHeader, SheetTitle } from "@/components/ui/sheet"
import { Select, SelectContent, SelectGroup, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Separator } from "@/components/ui/separator"
import { useRecordForm, useForeignKeyOptions } from "lemma-sdk/react"
import type { LemmaClient, Table, ColumnSchema } from "lemma-sdk"
import { typeBadgeClasses, enumPillClasses, isSystemField } from "./records-enum-utils"
import { shortenIdentifier } from "./records-display-utils"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
} from "./records-style-utils"
import { cn } from "@/lib/utils"

interface RecordFormSheetProps {
  client: LemmaClient
  podId?: string
  tableName: string
  table: Table
  recordId?: string
  submitVia?: "direct" | "function"
  submitFunctionName?: string
  hiddenFields?: string[]
  fieldOrder?: string[]
  fieldGroups?: Array<{ label: string; fields: string[] }>
  foreignKeyLabels?: Record<string, string>
  mode?: "inline" | "modal" | "sheet"
  appearance?: LemmaRecordsAppearance
  density?: LemmaRecordsDensity
  radius?: LemmaRecordsRadius
  onClose: () => void
  onSuccess: () => void
}

export function RecordFormSheet({
  client,
  podId,
  tableName,
  table,
  recordId,
  submitVia = "direct",
  submitFunctionName,
  hiddenFields = [],
  fieldOrder,
  fieldGroups,
  foreignKeyLabels,
  mode = "sheet",
  appearance = "default",
  density = "comfortable",
  radius = "lg",
  onClose,
  onSuccess,
}: RecordFormSheetProps) {
  const form = useRecordForm({
    client,
    podId,
    tableName,
    recordId: recordId || null,
    hiddenFields: [...hiddenFields, "id", "created_at", "updated_at", "creator_user_id", "sort_order"],
    submitVia,
    submitFunctionName,
    onSubmitSuccess: () => onSuccess(),
  })

  const isEdit = !!recordId
  const title = isEdit ? "Edit Record" : "New Record"

  const orderedFields = React.useMemo(() => {
    let fields = form.editableFields
    if (fieldOrder) {
      const ordered = fieldOrder
        .map((n) => fields.find((f) => f.name === n))
        .filter((f): f is typeof fields[number] => f !== undefined)
      const remaining = fields.filter((f) => !fieldOrder.includes(f.name))
      fields = [...ordered, ...remaining]
    }
    return fields
  }, [form.editableFields, fieldOrder])

  const content = (
    <div className="flex h-full flex-col">
      {mode === "modal" ? (
        <DialogHeader className={cn("shrink-0", formHeaderClassName(appearance, density))}>
          <DialogTitle className="text-lg font-semibold tracking-tight">{title}</DialogTitle>
          <DialogDescription>{table.name}</DialogDescription>
        </DialogHeader>
      ) : (
        <SheetHeader className={cn("shrink-0", formHeaderClassName(appearance, density))}>
          <SheetTitle className="text-lg font-semibold tracking-tight">{title}</SheetTitle>
          <SheetDescription>{table.name}</SheetDescription>
        </SheetHeader>
      )}

      <div className={cn("flex-1 overflow-y-auto", formBodyClassName(density))}>
        {fieldGroups ? (
          <div className="space-y-6">
            {fieldGroups.map((group, gi) => (
              <div key={gi}>
                <p className="text-[10px] font-semibold uppercase tracking-widest text-muted-foreground mb-3">
                  {group.label}
                </p>
                <div className="space-y-4">
                  {group.fields
                    .map((n) => orderedFields.find((f) => f.name === n))
                    .filter((f): f is typeof orderedFields[number] => f !== undefined)
                    .map((field) => (
                      <FormField
                        key={field.name}
                        field={field}
                        value={form.values[field.name]}
                        error={form.fieldErrors[field.name]}
                        onChange={(v) => form.setValue(field.name, v)}
                        client={client}
                        podId={podId}
                        tableName={tableName}
                        labelField={foreignKeyLabels?.[field.name]}
                        radius={radius}
                      />
                    ))}
                </div>
                {gi < fieldGroups.length - 1 && <Separator className="mt-6 bg-border/30" />}
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-4">
            {orderedFields.map((field) => (
              <FormField
                key={field.name}
                field={field}
                value={form.values[field.name]}
                error={form.fieldErrors[field.name]}
                onChange={(v) => form.setValue(field.name, v)}
                client={client}
                podId={podId}
                tableName={tableName}
                labelField={foreignKeyLabels?.[field.name]}
                radius={radius}
              />
            ))}
          </div>
        )}
      </div>

      <div className={cn("shrink-0", formFooterClassName(appearance, density))}>
        <div className="flex items-center justify-end gap-3">
          <Button variant="ghost" onClick={onClose}>
            Cancel
          </Button>
          <Button
            onClick={() => form.submit()}
            disabled={form.isSubmitting || form.isLoadingSchema}
          >
            {form.isSubmitting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            {isEdit ? "Save Changes" : "Create"}
          </Button>
        </div>
      </div>
    </div>
  )

  if (mode === "sheet") {
    return (
      <Sheet open onOpenChange={(open) => !open && onClose()}>
        <SheetContent className={cn("w-full sm:max-w-lg p-0 gap-0", overlaySurfaceClassName(appearance, radius))}>{content}</SheetContent>
      </Sheet>
    )
  }

  if (mode === "modal") {
    return (
      <Dialog open onOpenChange={(open) => !open && onClose()}>
        <DialogContent className={cn("max-w-lg p-0 gap-0", overlaySurfaceClassName(appearance, radius))}>{content}</DialogContent>
      </Dialog>
    )
  }

  return <div className={cn(appearance === "minimal" ? "bg-transparent" : "bg-card", overlaySurfaceClassName(appearance, radius))}>{content}</div>
}

function formHeaderClassName(appearance: LemmaRecordsAppearance, density: LemmaRecordsDensity) {
  return cn(
    appearance === "borderless" ? "border-b-0" : appearance === "minimal" ? "border-b border-border/15" : "border-b border-border/50",
    density === "compact" ? "px-4 py-3" : density === "spacious" ? "px-7 py-5" : "px-6 py-4",
  )
}

function formBodyClassName(density: LemmaRecordsDensity) {
  if (density === "compact") return "px-4 py-3"
  if (density === "spacious") return "px-7 py-6"
  return "px-6 py-4"
}

function formFooterClassName(appearance: LemmaRecordsAppearance, density: LemmaRecordsDensity) {
  return cn(
    appearance === "borderless"
      ? "border-t-0 bg-transparent"
      : appearance === "minimal"
        ? "border-t border-border/15 bg-transparent"
        : "border-t border-border/50 bg-muted/30",
    density === "compact" ? "px-4 py-2.5" : density === "spacious" ? "px-7 py-4" : "px-6 py-3",
  )
}

function overlaySurfaceClassName(appearance: LemmaRecordsAppearance, radius: LemmaRecordsRadius) {
  const radiusClassName = recordsRadiusClassName(radius, "overlay")
  if (appearance === "borderless") return cn(radiusClassName, "border-0 shadow-xl ring-0")
  if (appearance === "minimal") return cn(radiusClassName, "border-0 shadow-none ring-0")
  if (appearance === "contained") return cn(radiusClassName, "border-border/70 shadow-xl")
  return cn(radiusClassName, "border-border/50")
}

function FormField({
  field,
  value,
  error,
  onChange,
  client,
  podId,
  tableName,
  labelField,
  radius,
}: {
  field: { name: string; label: string; kind: string; column: ColumnSchema; required?: boolean; options?: string[]; foreignKey?: unknown }
  value: unknown
  error?: string
  onChange: (v: unknown) => void
  client: LemmaClient
  podId?: string
  tableName: string
  labelField?: string
  radius: LemmaRecordsRadius
}) {
  const fkOptions = useForeignKeyOptions({
    client,
    podId,
    tableName,
    columnName: field.name,
    labelField,
    enabled: field.kind === "foreign-key",
  })

  const label = field.label || field.name.replace(/_/g, " ")

  return (
    <div className="space-y-1.5">
      <div className="flex items-center gap-2">
        <Label className="text-xs font-semibold uppercase tracking-widest text-muted-foreground">
          {label}
          {field.required && <span className="ml-0.5 text-destructive">*</span>}
        </Label>
        <span className={typeBadgeClasses(field.column)}>
          {field.kind === "foreign-key" ? "ref" : field.column.type.toLowerCase()}
        </span>
      </div>

      {renderInput(field, value, onChange, fkOptions.options, radius)}

      {error && <p className="text-xs text-destructive">{error}</p>}
    </div>
  )
}

function renderInput(
  field: { name: string; kind: string; column: ColumnSchema; options?: string[] },
  value: unknown,
  onChange: (v: unknown) => void,
  fkOptions: Array<{ value: unknown; label: string }>,
  radius: LemmaRecordsRadius,
): React.ReactNode {
  const strVal = value == null ? "" : String(value)
  const placeholder = field.name.replace(/_/g, " ")

  if (field.kind === "foreign-key") {
    const selectedLabel = fkOptions.find((opt) => String(opt.value) === strVal)?.label
    return (
      <Select value={String(value ?? "")} onValueChange={(v) => onChange(v)}>
        <SelectTrigger className={cn("h-9", recordsRadiusClassName(radius, "control"))}>
          <SelectValue placeholder="Select…">
            {selectedLabel ?? (strVal ? shortenIdentifier(strVal) : undefined)}
          </SelectValue>
        </SelectTrigger>
        <SelectContent>
          <SelectGroup>
            {fkOptions.map((opt) => (
              <SelectItem key={String(opt.value)} value={String(opt.value)}>
                {opt.label}
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    )
  }

  if (field.kind === "select" && field.options?.length) {
    return (
      <Select value={strVal || undefined} onValueChange={(v) => onChange(v)}>
        <SelectTrigger className={cn("h-9", recordsRadiusClassName(radius, "control"))}>
          <SelectValue placeholder="Select…" />
        </SelectTrigger>
        <SelectContent>
          <SelectGroup>
            {field.options.map((opt) => (
              <SelectItem key={opt} value={opt}>
                <span className={enumPillClasses(opt, field.options!)}>{opt}</span>
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    )
  }

  if (field.kind === "boolean") {
    return (
      <div className="flex items-center gap-2 h-9">
        <Checkbox checked={Boolean(value)} onCheckedChange={(c) => onChange(c === true)} />
        <span className="text-sm text-muted-foreground">{value ? "Yes" : "No"}</span>
      </div>
    )
  }

  if (field.kind === "textarea") {
    return (
      <Textarea
        value={strVal}
        onChange={(e) => onChange(e.target.value)}
        rows={3}
        className={cn("resize-none border-border bg-background placeholder:text-muted-foreground focus-ring", recordsRadiusClassName(radius, "control"))}
      />
    )
  }

  if (field.kind === "number") {
    return (
      <Input
        type="number"
        value={strVal}
        onChange={(e) => onChange(e.target.value === "" ? null : Number(e.target.value))}
        className={cn("h-9 border-border bg-background placeholder:text-muted-foreground focus-ring", recordsRadiusClassName(radius, "control"))}
      />
    )
  }

  if (field.kind === "date") {
    return (
      <Input
        type="date"
        value={strVal}
        onChange={(e) => onChange(e.target.value || null)}
        className={cn("h-9 border-border bg-background placeholder:text-muted-foreground focus-ring", recordsRadiusClassName(radius, "control"))}
      />
    )
  }

  if (field.kind === "datetime") {
    return (
      <Input
        type="datetime-local"
        value={strVal}
        onChange={(e) => onChange(e.target.value || null)}
        className={cn("h-9 border-border bg-background placeholder:text-muted-foreground focus-ring", recordsRadiusClassName(radius, "control"))}
      />
    )
  }

  if (field.kind === "json") {
    return (
      <Textarea
        value={strVal}
        onChange={(e) => onChange(e.target.value)}
        rows={4}
        className={cn("font-mono text-xs resize-none border-border bg-background placeholder:text-muted-foreground focus-ring", recordsRadiusClassName(radius, "control"))}
        placeholder="{}"
      />
    )
  }

  return (
    <Input
      type="text"
      value={strVal}
      onChange={(e) => onChange(e.target.value)}
        className={cn("h-9 border-border bg-background placeholder:text-muted-foreground focus-ring", recordsRadiusClassName(radius, "control"))}
      placeholder={placeholder}
    />
  )
}

"use client"

import * as React from "react"
import {
  AlertCircle,
  Database,
  Filter,
  List,
  LayoutGrid,
  Plus,
  RefreshCw,
  Search,
  Trash2,
  MoreVertical,
  Rows3,
  X,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Checkbox } from "@/components/ui/checkbox"
import {
  Table as DataTable,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import {
  useTable,
  useRecords,
  useForeignKeyOptions,
} from "lemma-sdk/react"
import type { LemmaClient, ColumnSchema, RecordFilter, Table } from "lemma-sdk"
import { cn } from "@/lib/utils"
import { EditableCell } from "./records-editable-cell"
import { FilterBuilder } from "./records-filter-builder"
import { DetailSheet } from "./records-detail-sheet"
import { ListView } from "./records-list-view"
import { GroupedView } from "./records-grouped-view"
import { isSystemField, typeBadgeClasses } from "./records-enum-utils"
import { RecordFormSheet } from "./records-form-sheet"
import type { ForeignKeyLabelMap } from "./records-display-utils"
import type {
  RecordDetailRelatedRecord,
  RecordDetailTab,
  RecordDetailVariant,
} from "./records-detail"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
} from "./records-style-utils"

export type { LemmaRecordsAppearance, LemmaRecordsDensity, LemmaRecordsRadius } from "./records-style-utils"

type ViewMode = "grid" | "list" | "grouped" | "kanban" | "linear"
type ResolvedViewMode = "grid" | "list" | "kanban" | "linear"
type CreateMode = "sheet" | "modal" | "page"
type DetailMode = "sheet" | "modal" | "page"
type PaginationMode = "pagination" | "load-more" | "infinite"

export interface LemmaRecordsViewProps {
  client: LemmaClient
  podId?: string
  tableName: string
  enabled?: boolean

  visibleColumns?: string[]
  hiddenFields?: string[]
  renderCell?: (record: Record<string, unknown>, column: ColumnSchema, value: unknown) => React.ReactNode
  renderCard?: (record: Record<string, unknown>, columns: ColumnSchema[]) => React.ReactNode
  foreignKeyLabels?: Record<string, string>
  searchFields?: string[]
  searchPlaceholder?: string

  defaultView?: ViewMode
  appearance?: LemmaRecordsAppearance
  density?: LemmaRecordsDensity
  radius?: LemmaRecordsRadius
  groupBy?: string
  defaultFilters?: RecordFilter[]
  pageSize?: number
  paginationMode?: PaginationMode
  createMode?: CreateMode
  createRoute?: string | (() => string)
  detailMode?: DetailMode
  detailRoute?: (record: Record<string, unknown>) => string
  detailVariant?: RecordDetailVariant
  detailTabs?: RecordDetailTab[]
  detailRelatedRecords?: RecordDetailRelatedRecord[]
  detailEditable?: boolean

  onCreateOptions?: {
    submitVia?: "direct" | "function"
    submitFunctionName?: string
    hiddenFields?: string[]
  }
  onUpdateOptions?: {
    updateVia?: "direct" | "function"
    updateFunctionName?: string
  }

  title?: React.ReactNode
  headerActions?: React.ReactNode
  emptyState?: React.ReactNode
  className?: string
  onRecordClick?: (record: Record<string, unknown>) => void
}

export function LemmaRecordsView({
  client,
  podId,
  tableName,
  enabled = true,
  visibleColumns: visibleColumnNames,
  hiddenFields = [],
  renderCell,
  renderCard,
  foreignKeyLabels,
  searchFields,
  searchPlaceholder = "Search…",
  defaultView = "grid",
  appearance = "default",
  density = "comfortable",
  radius = "lg",
  groupBy: groupByProp,
  defaultFilters = [],
  pageSize = 50,
  paginationMode = "pagination",
  createMode = "sheet",
  createRoute,
  detailMode = "sheet",
  detailRoute,
  detailVariant = "workspace",
  detailTabs,
  detailRelatedRecords,
  detailEditable = true,
  onCreateOptions,
  onUpdateOptions,
  title,
  headerActions,
  emptyState,
  className,
  onRecordClick,
}: LemmaRecordsViewProps) {
  const [viewMode, setViewMode] = React.useState<ResolvedViewMode>(normalizeViewMode(defaultView))
  const [filters, setFilters] = React.useState<RecordFilter[]>(defaultFilters)
  const [showFilterBuilder, setShowFilterBuilder] = React.useState(false)
  const [search, setSearch] = React.useState("")
  const [selectedRows, setSelectedRows] = React.useState<Set<string>>(new Set())
  const [detailRecord, setDetailRecord] = React.useState<Record<string, unknown> | null>(null)
  const [showCreateForm, setShowCreateForm] = React.useState(false)
  const [foreignKeyLabelMap, setForeignKeyLabelMap] = React.useState<ForeignKeyLabelMap>({})
  const [page, setPage] = React.useState(0)
  const contentRef = React.useRef<HTMLDivElement | null>(null)
  const [infiniteSentinel, setInfiniteSentinel] = React.useState<HTMLDivElement | null>(null)

  const tableState = useTable({ client, podId, tableName, enabled })
  const table = tableState.table
  const queryFilters = React.useMemo(() => normalizeRecordFilters(filters), [filters])

  const recordsState = useRecords({
    client,
    podId,
    tableName,
    filters: queryFilters.length > 0 ? queryFilters : undefined,
    limit: pageSize,
    offset: paginationMode === "pagination" ? page * pageSize : 0,
    enabled: !!table && enabled,
  })

  const records = recordsState.records
  const total = recordsState.total
  const pk = table?.primary_key_column ?? "id"

  const resolvedColumns = React.useMemo(() => {
    if (!table) return []
    const cols = table.columns.filter((c) => !hiddenFields.includes(c.name))
    if (visibleColumnNames) {
      return visibleColumnNames
        .map((n) => cols.find((c) => c.name === n))
        .filter(Boolean) as ColumnSchema[]
    }
    return cols
  }, [table, visibleColumnNames, hiddenFields])

  const foreignKeyColumns = React.useMemo(
    () => resolvedColumns.filter((column) => !!column.foreign_key),
    [resolvedColumns],
  )

  const groupByColumn = React.useMemo(() => {
    if (!table) return null
    if (groupByProp) return table.columns.find((c) => c.name === groupByProp) ?? null
    return (
      table.columns.find((c) => /status|stage|state|priority|type|category/i.test(c.name) && c.type === "ENUM") ?? null
    )
  }, [table, groupByProp])

  const getRecordId = (r: Record<string, unknown>) => String(r[pk] ?? "")
  const deferredSearch = React.useDeferredValue(search)
  const searchQuery = deferredSearch.trim().toLowerCase()
  const searchableColumnNames = React.useMemo(() => {
    if (searchFields?.length) return searchFields
    return resolvedColumns.filter(isSearchableColumn).map((c) => c.name)
  }, [resolvedColumns, searchFields])
  const displayedRecords = React.useMemo(() => {
    if (!searchQuery) return records
    return records.filter((record) =>
      searchableColumnNames.some((name) => matchesSearchValue(record[name], searchQuery)),
    )
  }, [records, searchQuery, searchableColumnNames])
  const displayedRecordIds = React.useMemo(() => displayedRecords.map(getRecordId), [displayedRecords, pk])
  const allDisplayedSelected =
    displayedRecordIds.length > 0 && displayedRecordIds.every((id) => selectedRows.has(id))
  const hasSearch = searchQuery.length > 0
  const hasFilters = filters.length > 0
  const hasActiveConstraints = hasSearch || hasFilters
  const pageStart = total === 0 ? 0 : page * pageSize + 1
  const pageEnd = Math.min(page * pageSize + records.length, total)
  const isGroupedView = (viewMode === "kanban" || viewMode === "linear") && !!groupByColumn
  const canLoadMore = records.length < total || !!recordsState.nextPageToken
  const progressivePagination = paginationMode === "load-more" || paginationMode === "infinite"
  const detailRecordIndex = detailRecord
    ? displayedRecords.findIndex((r) => getRecordId(r) === getRecordId(detailRecord))
    : -1

  const applyFilters = (nextFilters: RecordFilter[]) => {
    setFilters(nextFilters)
    setPage(0)
    setSelectedRows(new Set())
  }

  const clearSearch = () => setSearch("")

  const clearAllConstraints = () => {
    setSearch("")
    applyFilters([])
  }

  const handleSelectAll = () => {
    if (allDisplayedSelected) {
      setSelectedRows((prev) => {
        const next = new Set(prev)
        for (const id of displayedRecordIds) next.delete(id)
        return next
      })
    } else {
      setSelectedRows((prev) => {
        const next = new Set(prev)
        for (const id of displayedRecordIds) next.add(id)
        return next
      })
    }
  }

  const handleSelectRow = (id: string) => {
    setSelectedRows((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const handleRecordClick = (record: Record<string, unknown>) => {
    if (onRecordClick) {
      onRecordClick(record)
      return
    }
    if (detailMode === "page" && detailRoute) {
      navigateTo(detailRoute(record))
      return
    }
    setDetailRecord(record)
  }

  const handleLoadMore = React.useCallback(async () => {
    if (!canLoadMore || recordsState.isLoading || recordsState.isLoadingMore) return
    await recordsState.loadMore()
  }, [canLoadMore, recordsState])

  React.useEffect(() => {
    if (paginationMode !== "infinite") return
    if (!infiniteSentinel || !canLoadMore || recordsState.isLoading || recordsState.isLoadingMore) return

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries.some((entry) => entry.isIntersecting)) {
          void handleLoadMore()
        }
      },
      { root: contentRef.current, rootMargin: "320px 0px" },
    )

    observer.observe(infiniteSentinel)
    return () => observer.disconnect()
  }, [
    canLoadMore,
    handleLoadMore,
    infiniteSentinel,
    paginationMode,
    recordsState.isLoading,
    recordsState.isLoadingMore,
  ])

  const handleCreateClick = () => {
    if (createMode === "page" && createRoute) {
      navigateTo(typeof createRoute === "function" ? createRoute() : createRoute)
      return
    }
    setShowCreateForm(true)
  }

  const handleDeleteSelected = async () => {
    const ids = Array.from(selectedRows)
    if (!confirm(`Delete ${ids.length} record(s)?`)) return
    for (const id of ids) {
      const scoped = podId ? client.withPod(podId) : client
      await scoped.records.delete(tableName, id)
    }
    setSelectedRows(new Set())
    recordsState.refresh()
  }

  const handleUpdateRecord = async (recordId: string, data: Record<string, unknown>) => {
    const scoped = podId ? client.withPod(podId) : client
    if (onUpdateOptions?.updateVia === "function") {
      await scoped.functions.runs.create(onUpdateOptions.updateFunctionName ?? tableName, {
        input: { ...data, id: recordId, record_id: recordId },
      })
    } else {
      await scoped.records.update(tableName, recordId, data)
    }
    recordsState.refresh()
  }

  const handleResolveForeignKeyLabels = React.useCallback((columnName: string, labels: Record<string, string>) => {
    setForeignKeyLabelMap((previous) => {
      if (shallowEqualLabelMap(previous[columnName], labels)) return previous
      return { ...previous, [columnName]: labels }
    })
  }, [])

  if (tableState.isLoading) {
    return (
      <div className={cn("flex h-64 items-center justify-center", recordsSurfaceClassName(appearance, radius))}>
        <div className="text-sm text-muted-foreground">Loading…</div>
      </div>
    )
  }

  if (!table) {
    return (
      <div className={cn("flex h-64 flex-col items-center justify-center px-6 text-center", recordsSurfaceClassName(appearance, radius, true))}>
        <p className="text-lg font-semibold text-foreground">Table not found</p>
        <p className="mt-1 text-sm text-muted-foreground">The table &quot;{tableName}&quot; could not be loaded.</p>
      </div>
    )
  }

  return (
    <div
      data-appearance={appearance}
      data-density={density}
      data-radius={radius}
      className={cn("lemma-records-view flex h-full min-h-0 flex-col", recordsRootClassName(appearance), className)}
    >
      {foreignKeyColumns.map((column) => (
        <ForeignKeyLabelResolver
          key={column.name}
          client={client}
          podId={podId}
          tableName={tableName}
          column={column}
          labelField={foreignKeyLabels?.[column.name]}
          onResolve={handleResolveForeignKeyLabels}
        />
      ))}

      <div className={cn("shrink-0 backdrop-blur-sm", recordsHeaderClassName(appearance))}>
        <div className={cn("flex flex-col lg:flex-row lg:items-center lg:justify-between", recordsToolbarClassName(density))}>
          <div className="min-w-0">
            <div className="flex items-center gap-2">
              <span className={cn("flex size-7 items-center justify-center border border-border/50 bg-muted/40 text-muted-foreground", recordsRadiusClassName(radius, "control"))}>
                <Database className="size-3.5" />
              </span>
              <div className="min-w-0">
                <h1 className="truncate text-sm font-semibold text-foreground">
                  {title ?? table.name}
                </h1>
                <p className="text-xs text-muted-foreground">
                  {hasSearch ? `${displayedRecords.length} matching on this page` : `${total} records`}
                </p>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <div className="relative w-full sm:w-auto">
              <Search className="absolute left-2.5 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" />
              <Input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder={searchPlaceholder}
                className={cn("h-8 w-full pl-8 pr-8 text-xs sm:w-56", recordsRadiusClassName(radius, "control"))}
              />
              {search && (
                <button
                  type="button"
                  onClick={clearSearch}
                  className={cn("absolute right-2 top-1/2 flex size-4 -translate-y-1/2 items-center justify-center text-muted-foreground transition-colors hover:bg-muted hover:text-foreground", recordsRadiusClassName(radius, "control"))}
                >
                  <X className="size-3" />
                  <span className="sr-only">Clear search</span>
                </button>
              )}
            </div>

            <div className={cn("mx-1 h-5 w-px bg-border/50", appearance === "borderless" && "hidden")} />

            <ViewModeToggle mode={viewMode} onChange={setViewMode} hasGroupBy={!!groupByColumn} radius={radius} />

            <Button
              variant="ghost"
              size="sm"
              onClick={() => setShowFilterBuilder(true)}
              className="h-8 gap-2 text-xs"
            >
              <Filter className="h-3.5 w-3.5 text-muted-foreground" />
              Filter{filters.length > 0 ? ` (${filters.length})` : ""}
            </Button>

            {hasActiveConstraints && (
              <Button
                variant="ghost"
                size="sm"
                onClick={clearAllConstraints}
                className="h-8 gap-2 text-xs text-muted-foreground"
              >
                <X className="h-3.5 w-3.5" />
                Clear
              </Button>
            )}

            {headerActions}

            <div className={cn("mx-1 h-5 w-px bg-border/50", appearance === "borderless" && "hidden")} />

            <Button
              size="sm"
              onClick={handleCreateClick}
              className="h-8 gap-2 text-xs"
            >
              <Plus className="h-3.5 w-3.5" />
              New
            </Button>
          </div>
        </div>

        {hasFilters && (
          <div className={cn("flex items-center gap-2 px-4 py-2 text-xs text-muted-foreground", appearance === "borderless" ? "border-t-0" : appearance === "minimal" ? "border-t border-border/15" : "border-t border-border/30")}>
            <span className="font-medium text-foreground">Filtered by</span>
            <div className="flex flex-wrap items-center gap-1.5">
              {filters.map((filter, index) => (
                <button
                  key={`${filter.field}-${filter.op}-${index}`}
                  type="button"
                  onClick={() => applyFilters(filters.filter((_, i) => i !== index))}
                  className="inline-flex items-center gap-1 rounded-full border border-border/60 bg-background px-2 py-0.5 text-foreground transition-colors hover:bg-muted/60"
                >
                  <span>{filter.field}</span>
                  <span className="text-muted-foreground">{filter.op}</span>
                  {filter.value != null && filter.value !== "" && <span>{String(filter.value)}</span>}
                  <X className="size-3 text-muted-foreground" />
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      {selectedRows.size > 0 && (
        <div className={cn("absolute left-1/2 top-20 z-30 flex -translate-x-1/2 items-center gap-4 rounded-full px-5 py-2.5 shadow-lg backdrop-blur-sm", recordsFloatingClassName(appearance))}>
          <span className="text-sm font-medium text-foreground">{selectedRows.size} selected</span>
          <div className="h-4 w-px bg-border" />
          <Button variant="ghost" size="sm" className="h-8 rounded-full" onClick={handleDeleteSelected}>
            <Trash2 className="mr-1.5 h-3.5 w-3.5 text-destructive" />
            Delete
          </Button>
        </div>
      )}

      <div ref={contentRef} className={cn("flex-1 overflow-auto", recordsContentClassName(density))}>
        {recordsState.error ? (
          <RecordsErrorState error={recordsState.error} radius={radius} onRetry={() => recordsState.refresh()} />
        ) : viewMode === "grid" ? (
          <div className={cn("overflow-auto", recordsSurfaceClassName(appearance, radius))}>
            <DataTable className="min-w-full table-fixed">
              <TableHeader className={cn("sticky top-0 z-10 backdrop-blur-md", appearance === "minimal" || appearance === "borderless" ? "border-b border-border/15 bg-background/80" : "border-b border-border/30 bg-card/95")}>
                <TableRow className="hover:bg-transparent">
                  <TableHead className="w-10 px-2 py-2 text-center">
                    <Checkbox
                      checked={allDisplayedSelected}
                      onCheckedChange={handleSelectAll}
                      className="h-4 w-4 rounded"
                    />
                  </TableHead>
                  {resolvedColumns.map((col) => (
                    <TableHead
                      key={col.name}
                      className={cn("px-3 text-left text-xs font-medium tracking-wide text-muted-foreground", density === "compact" ? "py-2" : density === "spacious" ? "py-3.5" : "py-2.5")}
                    >
                      <div className="flex items-center gap-1.5">
                        <span>{col.name.replace(/_/g, " ")}</span>
                        <span className={typeBadgeClasses(col)}>
                          {col.foreign_key ? "ref" : col.type.toLowerCase()}
                        </span>
                      </div>
                    </TableHead>
                  ))}
                  <TableHead className="w-10 px-2 py-2" />
                </TableRow>
              </TableHeader>
              <TableBody className="divide-y divide-border/20">
                {recordsState.isLoading ? (
                  <RecordsTableMessage colSpan={resolvedColumns.length + 2}>
                    <RefreshCw className="size-4 animate-spin" />
                    Loading records…
                  </RecordsTableMessage>
                ) : displayedRecords.length === 0 ? (
                  <RecordsTableMessage colSpan={resolvedColumns.length + 2}>
                    <EmptyRecordsState
                      constrained={hasActiveConstraints}
                      emptyState={emptyState}
                      radius={radius}
                      onClear={hasActiveConstraints ? clearAllConstraints : undefined}
                      onCreate={handleCreateClick}
                    />
                  </RecordsTableMessage>
                ) : (
                  displayedRecords.map((record) => {
                    const id = getRecordId(record)
                    const selected = selectedRows.has(id)
                    return (
                      <TableRow
                        key={id}
                        data-state={selected ? "selected" : undefined}
                        className={cn(
                          "group transition-colors duration-75",
                          selected && "bg-primary/5",
                        )}
                      >
                        <TableCell className="px-2 py-1 text-center">
                          <Checkbox
                            checked={selected}
                            onCheckedChange={() => handleSelectRow(id)}
                            className={cn(
                              "h-4 w-4 rounded opacity-0 transition-opacity group-hover:opacity-100",
                              selected && "opacity-100",
                            )}
                          />
                        </TableCell>
                        {resolvedColumns.map((col) => (
                          <TableCell key={col.name} className="px-0 py-0">
                            {renderCell ? (
                              renderCell(record, col, record[col.name])
                            ) : (
                              <EditableCell
                                value={record[col.name]}
                                column={col}
                                foreignKeyLabelMap={foreignKeyLabelMap[col.name]}
                                onSave={async (newValue) => {
                                  await handleUpdateRecord(id, { [col.name]: newValue })
                                }}
                              />
                            )}
                          </TableCell>
                        ))}
                        <TableCell className="px-2 py-1">
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleRecordClick(record)}
                            className="size-7 text-muted-foreground opacity-0 transition-all group-hover:opacity-100"
                          >
                            <MoreVertical className="size-3.5" />
                            <span className="sr-only">Open record details</span>
                          </Button>
                        </TableCell>
                      </TableRow>
                    )
                  })
                )}
              </TableBody>
            </DataTable>
          </div>
        ) : recordsState.isLoading ? (
          <RecordsLoadingState radius={radius} />
        ) : displayedRecords.length === 0 && !isGroupedView ? (
          <EmptyRecordsState
            constrained={hasActiveConstraints}
            emptyState={emptyState}
            radius={radius}
            onClear={hasActiveConstraints ? clearAllConstraints : undefined}
            onCreate={handleCreateClick}
          />
        ) : viewMode === "list" ? (
          <ListView
            records={displayedRecords}
            table={table}
            visibleColumns={resolvedColumns}
            selectedRecords={selectedRows}
            onSelectRecord={handleSelectRow}
            onRecordClick={handleRecordClick}
            renderCard={renderCard}
            foreignKeyLabelMap={foreignKeyLabelMap}
            appearance={appearance}
            density={density}
            radius={radius}
          />
        ) : (viewMode === "kanban" || viewMode === "linear") && groupByColumn ? (
          <GroupedView
            records={displayedRecords}
            groupByColumn={groupByColumn}
            layout={viewMode}
            primaryKey={pk}
            visibleColumns={resolvedColumns}
            selectedRecords={selectedRows}
            onSelectRecord={handleSelectRow}
            onRecordClick={handleRecordClick}
            renderCard={renderCard}
            foreignKeyLabelMap={foreignKeyLabelMap}
            appearance={appearance}
            density={density}
            radius={radius}
          />
        ) : null}

        {paginationMode === "infinite" && !recordsState.isLoading ? (
          <div ref={setInfiniteSentinel} className="h-px" />
        ) : null}
      </div>

      <div className={cn("shrink-0 px-4", recordsFooterClassName(appearance, density))}>
        <div className="flex items-center justify-between text-xs text-muted-foreground">
          <span>
            {progressivePagination
              ? hasSearch
                ? `Showing ${displayedRecords.length} matching loaded record(s)`
                : `Loaded ${records.length} of ${total}`
              : hasSearch
              ? `Showing ${displayedRecords.length} matching record(s) on this page`
              : `Showing ${pageStart}–${pageEnd} of ${total}`}
          </span>
          <div className="flex items-center gap-2">
            {progressivePagination ? (
              <Button
                variant="ghost"
                size="sm"
                className="h-7 text-xs"
                onClick={() => void handleLoadMore()}
                disabled={!canLoadMore || recordsState.isLoadingMore}
              >
                {recordsState.isLoadingMore ? <RefreshCw className="mr-1.5 size-3 animate-spin" /> : null}
                {canLoadMore ? "Load more" : "All loaded"}
              </Button>
            ) : (
              <>
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-7 text-xs"
                  onClick={() => setPage(Math.max(0, page - 1))}
                  disabled={page === 0}
                >
                  Previous
                </Button>
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-7 text-xs"
                  onClick={() => setPage(page + 1)}
                  disabled={page * pageSize + records.length >= total}
                >
                  Next
                </Button>
              </>
            )}
          </div>
        </div>
      </div>

      {showFilterBuilder && table && (
        <FilterBuilder
          columns={resolvedColumns}
          filters={filters}
          onApply={applyFilters}
          onClose={() => setShowFilterBuilder(false)}
        />
      )}

      {detailRecord && table && (
        <DetailSheet
          record={detailRecord}
          table={table}
          client={client}
          podId={podId}
          mode={detailMode === "modal" ? "modal" : "sheet"}
          variant={detailVariant}
          tabs={detailTabs}
          relatedRecords={detailRelatedRecords}
          editable={detailEditable}
          hiddenFields={hiddenFields}
          onClose={() => setDetailRecord(null)}
          onRecordChanged={() => recordsState.refresh()}
          updateVia={onUpdateOptions?.updateVia}
          updateFunctionName={onUpdateOptions?.updateFunctionName}
          onDelete={async () => {
            const id = getRecordId(detailRecord)
            const scoped = podId ? client.withPod(podId) : client
            await scoped.records.delete(tableName, id)
            setDetailRecord(null)
            recordsState.refresh()
          }}
          onNext={() => {
            if (detailRecordIndex >= 0 && detailRecordIndex < displayedRecords.length - 1) {
              setDetailRecord(displayedRecords[detailRecordIndex + 1])
            }
          }}
          onPrevious={() => {
            if (detailRecordIndex > 0) setDetailRecord(displayedRecords[detailRecordIndex - 1])
          }}
          hasPrevious={detailRecordIndex > 0}
          hasNext={detailRecordIndex >= 0 && detailRecordIndex < displayedRecords.length - 1}
          foreignKeyLabels={foreignKeyLabels}
          appearance={appearance}
          density={density}
          radius={radius}
        />
      )}

      {showCreateForm && table && (
        <RecordFormSheet
          client={client}
          podId={podId}
          tableName={tableName}
          table={table}
          submitVia={onCreateOptions?.submitVia}
          submitFunctionName={onCreateOptions?.submitFunctionName}
          hiddenFields={onCreateOptions?.hiddenFields ?? hiddenFields}
          foreignKeyLabels={foreignKeyLabels}
          mode={createMode === "modal" ? "modal" : "sheet"}
          appearance={appearance}
          density={density}
          radius={radius}
          onClose={() => setShowCreateForm(false)}
          onSuccess={() => {
            setShowCreateForm(false)
            recordsState.refresh()
          }}
        />
      )}
    </div>
  )
}

function normalizeViewMode(mode: ViewMode): ResolvedViewMode {
  return mode === "grouped" ? "kanban" : mode
}

function navigateTo(path: string): void {
  if (typeof window !== "undefined") {
    window.location.assign(path)
  }
}

function normalizeRecordFilters(filters: RecordFilter[]): RecordFilter[] {
  return filters.map((filter) => {
    const value = typeof filter.value === "string" ? filter.value.trim() : filter.value

    if (filter.op === "ilike" && typeof value === "string") {
      return { ...filter, value: `%${value}%` }
    }

    if (filter.op === "starts_with" && typeof value === "string") {
      return { ...filter, op: "ilike", value: `${value}%` }
    }

    if (filter.op === "ends_with" && typeof value === "string") {
      return { ...filter, op: "ilike", value: `%${value}` }
    }

    if (filter.op === "in" && typeof value === "string") {
      return {
        field: filter.field,
        op: "in",
        values: value.split(",").map((entry) => entry.trim()).filter(Boolean),
      }
    }

    if (filter.op === "is" || filter.op === "is not") {
      return { ...filter, value: null }
    }

    return { ...filter, value }
  })
}

function shallowEqualLabelMap(
  a: Record<string, string> | undefined,
  b: Record<string, string>,
): boolean {
  const aKeys = Object.keys(a ?? {})
  const bKeys = Object.keys(b)
  if (aKeys.length !== bKeys.length) return false
  return bKeys.every((key) => a?.[key] === b[key])
}

function ForeignKeyLabelResolver({
  client,
  podId,
  tableName,
  column,
  labelField,
  onResolve,
}: {
  client: LemmaClient
  podId?: string
  tableName: string
  column: ColumnSchema
  labelField?: string
  onResolve: (columnName: string, labels: Record<string, string>) => void
}) {
  const options = useForeignKeyOptions({
    client,
    podId,
    tableName,
    columnName: column.name,
    labelField,
    limit: 250,
    enabled: !!column.foreign_key,
  })

  React.useEffect(() => {
    const labels: Record<string, string> = {}
    for (const option of options.options) {
      labels[String(option.value)] = option.label
    }
    onResolve(column.name, labels)
  }, [column.name, onResolve, options.options])

  return null
}

function RecordsTableMessage({
  colSpan,
  children,
}: {
  colSpan: number
  children: React.ReactNode
}) {
  return (
    <TableRow className="hover:bg-transparent">
      <TableCell colSpan={colSpan} className="px-4 py-12">
        <div className="flex items-center justify-center gap-2 text-sm text-muted-foreground">
          {children}
        </div>
      </TableCell>
    </TableRow>
  )
}

function RecordsLoadingState({ radius }: { radius: LemmaRecordsRadius }) {
  return (
    <div className={cn("flex min-h-64 items-center justify-center border border-border/50 bg-card", recordsRadiusClassName(radius, "surface"))}>
      <div className="flex items-center gap-2 text-sm text-muted-foreground">
        <RefreshCw className="size-4 animate-spin" />
        Loading records…
      </div>
    </div>
  )
}

function RecordsErrorState({ error, radius, onRetry }: { error: Error; radius: LemmaRecordsRadius; onRetry: () => void }) {
  return (
    <div className={cn("flex min-h-64 flex-col items-center justify-center gap-3 border border-destructive/30 bg-destructive/5 px-6 text-center", recordsRadiusClassName(radius, "surface"))}>
      <div className={cn("flex size-10 items-center justify-center bg-destructive/10 text-destructive", recordsRadiusClassName(radius, "pill"))}>
        <AlertCircle className="size-5" />
      </div>
      <div>
        <p className="font-medium text-foreground">Records could not be loaded</p>
        <p className="mt-1 max-w-md text-sm text-muted-foreground">{error.message}</p>
      </div>
      <Button variant="outline" size="sm" onClick={onRetry}>
        <RefreshCw className="mr-2 size-3.5" />
        Retry
      </Button>
    </div>
  )
}

function EmptyRecordsState({
  constrained,
  emptyState,
  radius,
  onClear,
  onCreate,
}: {
  constrained: boolean
  emptyState?: React.ReactNode
  radius: LemmaRecordsRadius
  onClear?: () => void
  onCreate: () => void
}) {
  if (!constrained && emptyState) return <>{emptyState}</>

  return (
    <div className={cn("flex min-h-64 flex-col items-center justify-center gap-3 border border-dashed border-border bg-card/60 px-6 text-center", recordsRadiusClassName(radius, "surface"))}>
      <div className={cn("flex size-10 items-center justify-center border border-border/60 bg-muted/40 text-muted-foreground", recordsRadiusClassName(radius, "pill"))}>
        <Database className="size-5" />
      </div>
      <div>
        <p className="font-medium text-foreground">
          {constrained ? "No records match this view" : "No records yet"}
        </p>
        <p className="mt-1 max-w-sm text-sm text-muted-foreground">
          {constrained
            ? "Try clearing search or filters to broaden the table."
            : "Create the first record and this workspace will fill in automatically."}
        </p>
      </div>
      <div className="flex items-center gap-2">
        {onClear && (
          <Button variant="outline" size="sm" onClick={onClear}>
            Clear view
          </Button>
        )}
        <Button size="sm" onClick={onCreate}>
          <Plus className="mr-2 size-3.5" />
          New record
        </Button>
      </div>
    </div>
  )
}

function isSearchableColumn(column: ColumnSchema): boolean {
  return column.type !== "VECTOR"
}

function matchesSearchValue(value: unknown, query: string): boolean {
  if (value == null) return false
  if (typeof value === "string") return value.toLowerCase().includes(query)
  if (typeof value === "number" || typeof value === "boolean") {
    return String(value).toLowerCase().includes(query)
  }
  if (value instanceof Date) return value.toISOString().toLowerCase().includes(query)
  try {
    return JSON.stringify(value).toLowerCase().includes(query)
  } catch {
    return String(value).toLowerCase().includes(query)
  }
}

function ViewModeToggle({
  mode,
  onChange,
  hasGroupBy,
  radius,
}: {
  mode: ResolvedViewMode
  onChange: (m: ResolvedViewMode) => void
  hasGroupBy: boolean
